diffs.replacement:
{
  "name": "ACESSO VITALÍCIO",
  "description": "Uma plataforma educacional premium com design ultra moderno, cursos e e-books exclusivos com foco em desenvolvimento pessoal e finanças.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export type MaterialType = 'curso' | 'ebook';

export interface Comment {
  id: string;
  userName: string;
  text: string;
  timestamp: string;
}

export interface Material {
  id: string;
  title: string;
  type: MaterialType;
  category: string;
  description: string;
  imageUrl: string;
  views: number;
  comments: Comment[];
  isReadBy: string[]; // List of user IDs who marked as read
  gradient: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  isAdmin: boolean;
}

export const CATEGORIES = [
  'Desenvolvimento Pessoal',
  'Finanças',
  'Produtividade',
  'Bem-estar',
  'Marketing',
  'Filosofia',
  'Tecnologia'
];

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useEffect } from 'react';
import { 
  LogOut, 
  Search, 
  Grid, 
  List, 
  Book, 
  PlayCircle, 
  Plus, 
  Trash2, 
  Edit3, 
  User as UserIcon, 
  LayoutDashboard,
  MessageSquare,
  Eye,
  CheckCircle,
  X,
  Send,
  ArrowRight,
  TrendingUp,
  Settings,
  PieChart,
  Users
} from 'lucide-react';
import { User, Material, MaterialType, CATEGORIES, Comment } from './types';
import { INITIAL_MATERIALS } from './constants';

// Helper for generating random gradients
const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 via-pink-500 to-red-500',
    'from-blue-600 via-cyan-500 to-teal-500',
    'from-orange-500 via-red-500 to-pink-500',
    'from-green-500 via-emerald-500 to-teal-600',
    'from-indigo-600 via-purple-600 to-pink-600',
    'from-yellow-400 via-orange-500 to-red-500'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  // Auth States
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');

  // App Content States
  const [items, setItems] = useState<Material[]>(INITIAL_MATERIALS);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  // Admin UI States
  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '',
    type: 'curso',
    category: CATEGORIES[0],
    description: '',
    imageUrl: '',
  });

  // User Stats (Computed)
  const userProgress = useMemo(() => {
    if (!currentUser) return 0;
    const readCount = items.filter(item => item.isReadBy.includes(currentUser.id)).length;
    return items.length > 0 ? Math.round((readCount / items.length) * 100) : 0;
  }, [items, currentUser]);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           item.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const stats = useMemo(() => {
    return {
      totalMaterials: items.length,
      totalViews: items.reduce((acc, curr) => acc + curr.views, 0),
      totalComments: items.reduce((acc, curr) => acc + curr.comments.length, 0),
      coursesCount: items.filter(i => i.type === 'curso').length,
      ebooksCount: items.filter(i => i.type === 'ebook').length
    };
  }, [items]);

  // Auth Handlers
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      const admin: User = { id: 'admin-1', name: 'Administrator', email: authEmail, isAdmin: true };
      setCurrentUser(admin);
    } else {
      const user: User = { 
        id: Math.random().toString(36).substr(2, 9), 
        name: authName || 'Novo Usuário', 
        email: authEmail, 
        isAdmin: false 
      };
      setCurrentUser(user);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setAuthEmail('');
    setAuthPassword('');
    setAuthName('');
    setSelectedItem(null);
  };

  // Material Handlers
  const toggleRead = (id: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const isRead = item.isReadBy.includes(currentUser.id);
        return {
          ...item,
          isReadBy: isRead 
            ? item.isReadBy.filter(uid => uid !== currentUser.id)
            : [...item.isReadBy, currentUser.id]
        };
      }
      return item;
    }));
  };

  const handleAddOrUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return;

    if (isEditing && materialForm.id) {
      setItems(prev => prev.map(item => 
        item.id === materialForm.id ? { ...item, ...materialForm } as Material : item
      ));
    } else {
      const newItem: Material = {
        id: Math.random().toString(36).substr(2, 9),
        title: materialForm.title!,
        type: materialForm.type as MaterialType,
        category: materialForm.category!,
        description: materialForm.description || '',
        imageUrl: materialForm.imageUrl!,
        views: 0,
        comments: [],
        isReadBy: [],
        gradient: getRandomGradient()
      };
      setItems(prev => [newItem, ...prev]);
    }

    setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '' });
    setIsEditing(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Tem certeza que deseja deletar este material?')) {
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleComment = (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      userName: currentUser.name,
      text: text,
      timestamp: new Date().toLocaleDateString('pt-BR')
    };

    setItems(prev => prev.map(item => 
      item.id === selectedItem.id 
        ? { ...item, comments: [newComment, ...item.comments] }
        : item
    ));

    setSelectedItem(prev => prev ? { ...prev, comments: [newComment, ...prev.comments] } : null);
  };

  // Login Screen
  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-gradient-to-br from-black via-gray-900 to-indigo-950">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
          <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/20 blur-[120px] rounded-full"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-pink-600/20 blur-[120px] rounded-full"></div>
        </div>

        <div className="glass max-w-md w-full p-10 rounded-3xl animate-float">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-gradient-primary tracking-tight mb-2">ACESSO VITALÍCIO</h1>
            <p className="text-gray-400 font-medium">Sua jornada de mestre começa aqui.</p>
          </div>

          <form onSubmit={handleAuth} className="space-y-4">
            {isAuthMode === 'register' && (
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1.5 ml-1">Nome Completo</label>
                <input 
                  type="text" 
                  value={authName}
                  onChange={e => setAuthName(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all"
                  placeholder="Seu nome"
                  required
                />
              </div>
            )}
            <div>
              <label className="block text-sm font-semibold text-gray-300 mb-1.5 ml-1">E-mail</label>
              <input 
                type="email" 
                value={authEmail}
                onChange={e => setAuthEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all"
                placeholder="seu@email.com"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-300 mb-1.5 ml-1">Senha</label>
              <input 
                type="password" 
                value={authPassword}
                onChange={e => setAuthPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all"
                placeholder="••••••••"
                required
              />
            </div>

            <button 
              type="submit"
              className="w-full py-4 rounded-xl bg-gradient-primary text-white font-bold text-lg hover:shadow-[0_0_20px_rgba(147,51,234,0.4)] transition-all transform hover:scale-[1.02] active:scale-95 mt-4"
            >
              {isAuthMode === 'login' ? 'Entrar Agora' : 'Criar Conta'}
            </button>
          </form>

          <div className="mt-8 text-center text-sm text-gray-400">
            {isAuthMode === 'login' ? (
              <p>Não tem uma conta? <button onClick={() => setIsAuthMode('register')} className="text-purple-400 font-bold hover:underline">Cadastre-se</button></p>
            ) : (
              <p>Já possui conta? <button onClick={() => setIsAuthMode('login')} className="text-purple-400 font-bold hover:underline">Fazer Login</button></p>
            )}
          </div>
        </div>
      </div>
    );
  }

  // Header & Sidebar Wrapper for Main Dashboard
  const DashboardLayout = ({ children }: { children: React.ReactNode }) => (
    <div className="min-h-screen bg-[#05070a] text-white flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className={`w-full md:w-72 glass-card border-r border-white/5 p-6 space-y-8 overflow-y-auto ${currentUser.isAdmin ? 'border-red-500/20' : ''}`}>
        <div className="flex items-center gap-3 mb-4">
          <div className={`p-2 rounded-lg bg-gradient-primary shadow-lg`}>
            <LayoutDashboard size={24} className="text-white" />
          </div>
          <h2 className="text-xl font-black tracking-tight text-gradient-primary">ACESSO VITALÍCIO</h2>
        </div>

        {/* User Profile Card */}
        <div className="p-4 rounded-2xl glass border border-white/10 space-y-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-600 flex items-center justify-center font-bold text-lg">
              {currentUser.name[0]}
            </div>
            <div>
              <p className="font-bold text-sm truncate w-32">{currentUser.name}</p>
              <p className="text-xs text-gray-500">{currentUser.isAdmin ? 'Admin' : 'Membro VIP'}</p>
            </div>
          </div>
          {!currentUser.isAdmin && (
            <div className="space-y-1.5">
              <div className="flex justify-between text-[10px] font-bold text-gray-400 uppercase tracking-wider">
                <span>Progresso</span>
                <span>{userProgress}%</span>
              </div>
              <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-primary rounded-full transition-all duration-1000" 
                  style={{ width: `${userProgress}%` }}
                ></div>
              </div>
            </div>
          )}
        </div>

        {/* Categories / Filters */}
        <div className="space-y-2">
          <p className="text-[10px] font-bold text-gray-500 uppercase tracking-[2px] ml-1">Categorias</p>
          {['Todos', ...CATEGORIES].map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`w-full text-left px-4 py-2.5 rounded-xl text-sm font-semibold transition-all flex items-center gap-3 ${
                activeCategory === cat 
                  ? 'bg-white/10 text-white border border-white/10 shadow-lg' 
                  : 'text-gray-400 hover:text-white hover:bg-white/5'
              }`}
            >
              <div className={`w-2 h-2 rounded-full ${activeCategory === cat ? 'bg-purple-500 shadow-[0_0_8px_rgba(168,85,247,0.8)]' : 'bg-gray-600'}`}></div>
              {cat}
            </button>
          ))}
        </div>

        {currentUser.isAdmin && (
          <div className="space-y-4 pt-4 border-t border-white/5">
            <p className="text-[10px] font-bold text-red-500 uppercase tracking-[2px] ml-1">Admin Panel</p>
            <div className="grid grid-cols-1 gap-3">
              <div className="p-3 rounded-xl bg-white/5 border border-white/5">
                <p className="text-xs text-gray-500">Total Materiais</p>
                <p className="text-xl font-bold">{stats.totalMaterials}</p>
              </div>
              <div className="p-3 rounded-xl bg-white/5 border border-white/5">
                <p className="text-xs text-gray-500">Visualizações</p>
                <p className="text-xl font-bold">{stats.totalViews}</p>
              </div>
            </div>
          </div>
        )}

        <button 
          onClick={handleLogout}
          className="w-full mt-auto flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-white/5 text-red-400 font-bold hover:bg-red-500/10 transition-all border border-red-500/10"
        >
          <LogOut size={18} />
          Sair do Portal
        </button>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto bg-gradient-to-b from-gray-950 to-black scrollbar-hide">
        {/* Top Navbar */}
        <header className="sticky top-0 z-30 px-6 py-4 glass border-b border-white/5 flex items-center justify-between">
          <div className="flex-1 max-w-xl">
            <div className="relative group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-purple-400 transition-colors" size={20} />
              <input 
                type="text" 
                placeholder="Busque por cursos, ebooks ou conteúdos..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500/50 transition-all focus:bg-white/10"
              />
            </div>
          </div>

          <div className="flex items-center gap-4 ml-6">
            <div className="hidden sm:flex bg-white/5 p-1 rounded-xl border border-white/5">
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                <Grid size={20} />
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                <List size={20} />
              </button>
            </div>
          </div>
        </header>

        <div className="p-8 pb-32">
          {children}
        </div>
      </main>

      {/* Comment Sidebar */}
      {selectedItem && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setSelectedItem(null)}></div>
          <div className="relative w-full max-w-lg h-full bg-[#0d1117] shadow-2xl border-l border-white/10 flex flex-col transform transition-transform animate-slide-in">
            <div className="p-6 border-b border-white/10 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className={`p-3 rounded-xl bg-gradient-to-br ${selectedItem.gradient}`}>
                  {selectedItem.type === 'curso' ? <PlayCircle size={24} /> : <Book size={24} />}
                </div>
                <div>
                  <h3 className="font-bold text-lg leading-tight">{selectedItem.title}</h3>
                  <p className="text-xs text-gray-500">{selectedItem.comments.length} comentários</p>
                </div>
              </div>
              <button onClick={() => setSelectedItem(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-hide">
              {selectedItem.comments.length > 0 ? (
                selectedItem.comments.map(comment => (
                  <div key={comment.id} className="glass p-4 rounded-2xl border border-white/5">
                    <div className="flex items-center justify-between mb-2">
                      <span className="font-bold text-purple-400 text-sm">{comment.userName}</span>
                      <span className="text-[10px] text-gray-500">{comment.timestamp}</span>
                    </div>
                    <p className="text-sm text-gray-300 leading-relaxed">{comment.text}</p>
                  </div>
                ))
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-50">
                  <MessageSquare size={48} className="mb-4 text-gray-600" />
                  <p className="font-medium text-gray-400">Nenhum comentário ainda.<br/>Seja o primeiro a participar!</p>
                </div>
              )}
            </div>

            <div className="p-6 border-t border-white/10 bg-[#0d1117]">
              <form 
                className="flex gap-2"
                onSubmit={(e) => {
                  const input = (e.target as any).comment;
                  handleComment(e, input.value);
                  input.value = '';
                }}
              >
                <input 
                  name="comment"
                  type="text" 
                  placeholder="Escreva sua dúvida ou insight..."
                  className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-1 focus:ring-purple-500"
                />
                <button 
                  type="submit"
                  className="p-3 bg-gradient-primary rounded-xl text-white hover:shadow-lg transition-all"
                >
                  <Send size={20} />
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // Admin Dashboard Component
  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="space-y-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-3xl font-black mb-1">Painel Admin</h1>
              <p className="text-gray-500">Gerencie conteúdos e acompanhe métricas da plataforma.</p>
            </div>
            <div className="flex gap-3">
              <div className="px-4 py-2 rounded-xl glass border border-red-500/20 flex items-center gap-2">
                <Users size={18} className="text-red-500" />
                <span className="font-bold text-sm">2,4k Alunos</span>
              </div>
              <div className="px-4 py-2 rounded-xl glass border border-blue-500/20 flex items-center gap-2">
                <TrendingUp size={18} className="text-blue-500" />
                <span className="font-bold text-sm">+15% Crescimento</span>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Form Section */}
            <div className="lg:col-span-1">
              <div className="glass-card p-6 rounded-3xl border border-white/10 sticky top-24">
                <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                  {isEditing ? <Edit3 size={20} /> : <Plus size={20} />}
                  {isEditing ? 'Editar Material' : 'Novo Material'}
                </h3>

                <form onSubmit={handleAddOrUpdate} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Título</label>
                    <input 
                      type="text" 
                      value={materialForm.title}
                      onChange={e => setMaterialForm({...materialForm, title: e.target.value})}
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-purple-500"
                      placeholder="Ex: Marketing para Iniciantes"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Tipo</label>
                      <select 
                        value={materialForm.type}
                        onChange={e => setMaterialForm({...materialForm, type: e.target.value as MaterialType})}
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-3 text-sm focus:ring-2 focus:ring-purple-500"
                      >
                        <option value="curso">Vídeo Curso</option>
                        <option value="ebook">E-book</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Categoria</label>
                      <select 
                        value={materialForm.category}
                        onChange={e => setMaterialForm({...materialForm, category: e.target.value})}
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-3 text-sm focus:ring-2 focus:ring-purple-500"
                      >
                        {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </div>
                  </div>

                  <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">URL da Imagem</label>
                    <input 
                      type="text" 
                      value={materialForm.imageUrl}
                      onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})}
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-purple-500"
                      placeholder="https://..."
                    />
                  </div>

                  {materialForm.imageUrl && (
                    <div className="w-full h-32 rounded-xl overflow-hidden border border-white/10">
                      <img src={materialForm.imageUrl} className="w-full h-full object-cover" alt="Preview" />
                    </div>
                  )}

                  <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Descrição</label>
                    <textarea 
                      value={materialForm.description}
                      onChange={e => setMaterialForm({...materialForm, description: e.target.value})}
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm h-24 focus:ring-2 focus:ring-purple-500"
                      placeholder="Breve descrição do conteúdo..."
                    ></textarea>
                  </div>

                  <div className="flex gap-3 pt-4">
                    <button 
                      type="submit" 
                      className="flex-1 bg-gradient-primary py-3 rounded-xl font-bold hover:shadow-[0_0_15px_rgba(147,51,234,0.3)] transition-all"
                    >
                      {isEditing ? 'Atualizar' : 'Adicionar Conteúdo'}
                    </button>
                    {isEditing && (
                      <button 
                        type="button"
                        onClick={() => {
                          setIsEditing(false);
                          setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '' });
                        }}
