            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
            <input type="text" placeholder="O que você deseja aprender hoje?" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-[2rem] pl-14 pr-6 py-4 text-sm outline-none focus:ring-2 focus:ring-purple-500/50 transition-all" />
          </div>
          <div className="flex items-center gap-6 ml-10">
            <div className="flex bg-white/5 p-1 rounded-2xl">
              <button onClick={() => setViewMode('grid')} className={`p-2.5 rounded-xl ${viewMode === 'grid' ? 'bg-purple-600 shadow-lg' : 'text-gray-500'}`}><Grid size={18}/></button>
              <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-xl ${viewMode === 'list' ? 'bg-purple-600 shadow-lg' : 'text-gray-500'}`}><List size={18}/></button>
            </div>
            <button className="relative p-3 rounded-xl bg-white/5 hover:bg-white/10 transition-all">
              <Bell size={20} className="text-gray-400" />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-black"></span>
            </button>
          </div>
        </header>

        <div className="p-10 pb-32">
          {children}
        </div>
      </main>

      {/* Enhanced Content Viewer (Modal Cinema) */}
      {selectedItem && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 md:p-12 overflow-hidden">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-3xl animate-fade-in" onClick={() => { setSelectedItem(null); setIsViewing(false); }}></div>

          <div className="relative w-full max-w-7xl h-full flex flex-col md:flex-row glass border border-white/10 rounded-[3rem] shadow-[0_0_100px_rgba(147,51,234,0.3)] animate-slide-in overflow-hidden">
            {/* Player Area */}
            <div className="flex-1 bg-black flex flex-col min-h-0">
              <div className="p-6 border-b border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-2xl bg-gradient-to-br ${selectedItem.gradient}`}>
                    {selectedItem.type === 'curso' ? <PlayCircle size={22} /> : <Book size={22} />}
                  </div>
                  <div>
                    <h2 className="text-xl font-black truncate max-w-md">{selectedItem.title}</h2>
                    <p className="text-xs text-purple-400 font-bold uppercase tracking-widest">{selectedItem.type} &bull; {selectedItem.category}</p>
                  </div>
                </div>
                <button onClick={() => { setSelectedItem(null); setIsViewing(false); }} className="p-3 bg-white/5 rounded-full hover:bg-white/10 transition-all"><X size={24} /></button>
              </div>

              <div className="flex-1 p-8 overflow-y-auto">
                <div className="aspect-video w-full rounded-3xl bg-gray-900 border border-white/5 overflow-hidden relative group mb-8">
                  {selectedItem.type === 'curso' ? (
                    <div className="w-full h-full flex items-center justify-center relative">
                      <img src={selectedItem.imageUrl} className="absolute inset-0 w-full h-full object-cover opacity-30 blur-sm" />
                      <div className="relative z-10 flex flex-col items-center gap-4">
                         <PlayCircle size={80} className="text-white opacity-80 group-hover:scale-110 transition-transform" />
                         <span className="font-black text-white/50 tracking-widest uppercase">Clique para iniciar a aula</span>
                      </div>
                    </div>
                  ) : (
                    <div className="w-full h-full p-12 bg-white/5 overflow-y-auto space-y-6">
                      <h1 className="text-4xl font-black mb-10">{selectedItem.title}</h1>
                      <div className="h-4 w-3/4 bg-white/10 rounded-full animate-pulse"></div>
                      <div className="h-4 w-full bg-white/5 rounded-full"></div>
                      <div className="h-4 w-5/6 bg-white/10 rounded-full"></div>
                      <p className="text-xl text-gray-400 pt-10 font-medium leading-relaxed italic border-l-4 border-purple-500 pl-8">
                        "O conhecimento é a única ferramenta que ninguém pode tirar de você. Domine cada página, cada linha."
                      </p>
                      <div className="h-4 w-full bg-white/5 rounded-full"></div>
                      <div className="h-4 w-3/4 bg-white/10 rounded-full"></div>
                    </div>
                  )}
                </div>
                <div className="max-w-4xl">
                   <h3 className="text-2xl font-black mb-4">Sobre este conteúdo</h3>
                   <p className="text-gray-400 leading-relaxed text-lg mb-8">{selectedItem.description}</p>
                   <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                      <div className="glass p-5 rounded-2xl border border-white/5 flex items-center gap-4">
                        <Users size={20} className="text-purple-400" />
                        <div><p className="text-xs text-gray-500 font-bold uppercase">Alunos</p><p className="font-bold">{selectedItem.views}</p></div>
                      </div>
                      <div className="glass p-5 rounded-2xl border border-white/5 flex items-center gap-4">
                        <Calendar size={20} className="text-pink-400" />
                        <div><p className="text-xs text-gray-500 font-bold uppercase">Publicado</p><p className="font-bold">Há 2 dias</p></div>
                      </div>
                      <div className="glass p-5 rounded-2xl border border-white/5 flex items-center gap-4">
                        <Maximize2 size={20} className="text-blue-400" />
                        <div><p className="text-xs text-gray-500 font-bold uppercase">Qualidade</p><p className="font-bold">4K Ultra HD</p></div>
                      </div>
                   </div>
                </div>
              </div>
            </div>

            {/* Comments Sidebar in Modal */}
            <div className="w-full md:w-[400px] border-l border-white/5 bg-[#05070a] flex flex-col min-h-0">
              <div className="p-8 border-b border-white/5 flex items-center justify-between">
                <h3 className="text-xl font-black flex items-center gap-3">
                  <MessageSquare size={20} className="text-purple-500" />
                  Comentários
                </h3>
                <span className="px-3 py-1 bg-white/5 rounded-full text-xs font-black text-gray-400">{selectedItem.comments.length}</span>
              </div>
              <div className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide">
                {selectedItem.comments.length > 0 ? (
                  selectedItem.comments.map(c => (
                    <div key={c.id} className="space-y-2 group">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-black text-purple-400">{c.userName}</span>
                        <span className="text-[10px] text-gray-600 font-bold">{c.timestamp}</span>
                      </div>
                      <div className="p-4 rounded-2xl bg-white/[0.03] border border-white/5 text-sm text-gray-300 group-hover:bg-white/[0.05] transition-all">
                        {c.text}
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="h-full flex flex-col items-center justify-center opacity-30 text-center">
                    <MessageSquare size={48} className="mb-4" />
                    <p className="font-bold text-sm">Nada por aqui ainda.<br/>Inicie o debate!</p>
                  </div>
                )}
              </div>
              <div className="p-8 border-t border-white/5">
                <form className="relative" onSubmit={(e) => {
                  const input = (e.target as any).comment;
                  handleComment(e, input.value);
                  input.value = '';
                }}>
                  <input name="comment" type="text" placeholder="Compartilhe seu insight..." 
                    className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none focus:ring-1 focus:ring-purple-500 transition-all pr-14" />
                  <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 p-2 bg-gradient-primary rounded-xl text-white shadow-lg">
                    <Send size={18} />
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // Admin Dashboard Component
  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="space-y-12 animate-fade-in">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div>
              <h1 className="text-4xl font-black mb-2 tracking-tighter">Command Center</h1>
              <p className="text-gray-500 font-medium">Controle total sobre o ecossistema Vitalício.</p>
            </div>
            <div className="flex gap-4">
              <div className="px-6 py-3 rounded-2xl glass border border-purple-500/20 flex items-center gap-3">
                 <div className="w-2 h-2 rounded-full bg-purple-500 animate-pulse shadow-[0_0_8px_#A855F7]"></div>
                 <span className="font-black text-sm uppercase tracking-widest">Servidor Online</span>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
             {[
               { label: 'Total Materiais', val: stats.totalMaterials, icon: Layers, color: 'text-purple-400', progress: 85 },
               { label: 'E-books Ativos', val: stats.ebooksCount, icon: Book, color: 'text-blue-400', progress: 40 },
               { label: 'Cursos Vídeo', val: stats.coursesCount, icon: PlayCircle, color: 'text-pink-400', progress: 60 },
               { label: 'Comentários', val: stats.totalComments, icon: MessageSquare, color: 'text-orange-400', progress: 72 }
             ].map((s, i) => (
               <div key={i} className="glass-card p-6 rounded-[2rem] border border-white/5 hover:border-white/10 transition-all group">
                 <div className="flex items-center justify-between mb-6">
                   <div className={`p-3 rounded-2xl bg-white/5 group-hover:scale-110 transition-transform ${s.color}`}>
