                 <p className="text-[10px] font-black uppercase text-gray-500 tracking-widest mb-1">{s.label}</p>
                 <h4 className="text-3xl font-black mb-4">{s.val}</h4>
                 <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                    <div className={`h-full bg-current rounded-full ${s.color}`} style={{ width: `${s.progress}%` }}></div>
