              <form onSubmit={handleAddOrUpdate} className="space-y-5">
                <input type="text" placeholder="Título Magnético" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none focus:ring-2 focus:ring-purple-500" />

                <div className="grid grid-cols-2 gap-4">
                   <select value={materialForm.type} onChange={e => setMaterialForm({...materialForm, type: e.target.value as MaterialType})}
                     className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-4 text-sm outline-none focus:ring-2 focus:ring-purple-500 appearance-none">
