                      <div className="flex items-center justify-between mb-6 pt-4 border-t border-white/5">
                        <div className="flex items-center gap-4">
                           <span className="text-[10px] font-black uppercase text-gray-500 flex items-center gap-1.5"><Eye size={12}/> {item.views}</span>
                           <span className="text-[10px] font-black uppercase text-gray-500 flex items-center gap-1.5"><MessageSquare size={12}/> {item.comments.length}</span>
                        </div>
                        <button onClick={() => toggleRead(item.id)} className={`p-2 transition-all ${isRead ? 'text-green-400' : 'text-gray-700 hover:text-white'}`}>
                          <CheckCircle size={22} fill={isRead ? 'currentColor' : 'none'} className={isRead ? 'fill-green-400/10' : ''} />
                        </button>
                      </div>

                      <button onClick={() => setSelectedItem(item)}
                        className={`w-full py-4 rounded-2xl font-black text-[11px] uppercase tracking-[2px] transition-all flex items-center justify-center gap-3 ${
                          item.type === 'curso' ? 'bg-purple-600/10 text-purple-400 hover:bg-purple-600 hover:text-white' : 'bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white'
