                </div>
                <div className="flex-1 min-w-0 text-center md:text-left">
                  <div className="flex flex-col md:flex-row md:items-center gap-3 mb-2">
                    <h3 className="text-xl font-black group-hover:text-purple-400 transition-colors">{item.title}</h3>
                    {isRead && <span className="text-[9px] bg-green-500/10 text-green-400 px-3 py-1 rounded-full font-black uppercase tracking-widest border border-green-500/20 w-fit mx-auto md:mx-0">Concluído</span>}
                  </div>
                  <p className="text-gray-500 text-sm line-clamp-1 italic">{item.description}</p>
                </div>
                <div className="flex flex-col md:flex-row items-center gap-8">
                  <div className="flex gap-6">
                    <span className="text-[10px] font-black uppercase text-gray-500 flex items-center gap-1.5"><Eye size={12}/> {item.views}</span>
                    <span className="text-[10px] font-black uppercase text-gray-500 flex items-center gap-1.5"><MessageSquare size={12}/> {item.comments.length}</span>
                  </div>
                  <button onClick={() => setSelectedItem(item)} className="px-8 py-4 rounded-2xl bg-white/5 border border-white/10 font-black text-[11px] uppercase tracking-widest hover:bg-purple-600 hover:text-white transition-all">Acessar</button>
