import React, { useState, useMemo, useEffect } from 'react';
import { 
  LogOut, 
  Search, 
  Grid, 
  List, 
  Book, 
  PlayCircle, 
  Plus, 
  Trash2, 
  Edit3, 
  LayoutDashboard,
  MessageSquare,
  Eye,
  CheckCircle,
  X,
  Send,
  ArrowRight,
  TrendingUp,
  Users,
  Bell,
  MoreVertical,
  Maximize2,
  Calendar,
  Layers,
  Star,
  ShieldCheck
} from 'lucide-react';
import { User, Material, MaterialType, CATEGORIES, CATEGORY_ICONS, Comment } from './types';
import { INITIAL_MATERIALS } from './constants';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');

  const [items, setItems] = useState<Material[]>(INITIAL_MATERIALS);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);
  const [isViewing, setIsViewing] = useState(false);

  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '',
    type: 'curso',
    category: CATEGORIES[0],
    description: '',
    imageUrl: '',
  });

  const [toasts, setToasts] = useState<{id: string, message: string}[]>([]);

  const addToast = (message: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  };

  const userProgress = useMemo(() => {
    if (!currentUser) return 0;
    const readCount = items.filter(item => item.isReadBy.includes(currentUser.id)).length;
    return items.length > 0 ? Math.round((readCount / items.length) * 100) : 0;
  }, [items, currentUser]);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           item.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const stats = useMemo(() => {
    return {
      totalMaterials: items.length,
      totalViews: items.reduce((acc, curr) => acc + curr.views, 0),
      totalComments: items.reduce((acc, curr) => acc + curr.comments.length, 0),
      coursesCount: items.filter(i => i.type === 'curso').length,
      ebooksCount: items.filter(i => i.type === 'ebook').length
    };
  }, [items]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin-1', name: 'Administrator', email: authEmail, isAdmin: true });
      addToast("Bem-vindo de volta, Diretor! 🛡️");
    } else {
      setCurrentUser({ 
        id: Math.random().toString(36).substr(2, 9), 
        name: authName || 'Novo Usuário', 
        email: authEmail, 
        isAdmin: false 
      });
      addToast("Acesso Vitalício Liberado! 🚀");
    }
  };

  const fillAdmin = () => {
    setAuthEmail('admin@academia.com');
    setAuthPassword('admin123');
    setIsAuthMode('login');
  };

  const toggleRead = (id: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const isRead = item.isReadBy.includes(currentUser.id);
        addToast(isRead ? "Removido do progresso" : "Marcado como concluído! ✅");
        return {
          ...item,
          isReadBy: isRead 
            ? item.isReadBy.filter(uid => uid !== currentUser.id)
            : [...item.isReadBy, currentUser.id]
        };
      }
      return item;
    }));
  };

  const handleAddOrUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return;

    if (isEditing && materialForm.id) {
      setItems(prev => prev.map(item => 
        item.id === materialForm.id ? { ...item, ...materialForm } as Material : item
      ));
      addToast("Material atualizado com sucesso!");
    } else {
      const newItem: Material = {
        id: Math.random().toString(36).substr(2, 9),
        title: materialForm.title!,
        type: materialForm.type as MaterialType,
        category: materialForm.category!,
        description: materialForm.description || '',
        imageUrl: materialForm.imageUrl!,
        views: 0,
        comments: [],
        isReadBy: [],
        gradient: getRandomGradient()
      };
      setItems(prev => [newItem, ...prev]);
      addToast("Novo material publicado! 🚀");
    }
    setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '' });
    setIsEditing(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Tem certeza que deseja deletar este material?')) {
      setItems(prev => prev.filter(item => item.id !== id));
      addToast("Material deletado.");
    }
  };

  const handleComment = (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      userName: currentUser.name,
      text: text,
      timestamp: new Date().toLocaleDateString('pt-BR')
    };

    setItems(prev => prev.map(item => 
      item.id === selectedItem.id 
        ? { ...item, comments: [newComment, ...item.comments] }
        : item
    ));
    setSelectedItem(prev => prev ? { ...prev, comments: [newComment, ...prev.comments] } : null);
    addToast("Comentário enviado! 💬");
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:rotate-12 transition-transform">
             <Star size={120} className="text-purple-500" />
          </div>
          <div className="text-center mb-8 relative z-10">
            <h1 className="text-4xl font-black text-gradient-primary tracking-tighter mb-2">ACESSO VITALÍCIO</h1>
            <p className="text-gray-400 font-medium">Domine o futuro com maestria.</p>
          </div>
          <form onSubmit={handleAuth} className="space-y-4 relative z-10">
            {isAuthMode === 'register' && (
              <input type="text" placeholder="Seu nome" value={authName} onChange={e => setAuthName(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            )}
            <input type="email" placeholder="seu@email.com" value={authEmail} onChange={e => setAuthEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            <input type="password" placeholder="••••••••" value={authPassword} onChange={e => setAuthPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            <button type="submit" className="w-full py-4 rounded-2xl bg-gradient-primary text-white font-bold text-lg hover:shadow-[0_0_30px_rgba(147,51,234,0.5)] transition-all transform hover:scale-[1.02] active:scale-95">
              {isAuthMode === 'login' ? 'Entrar na Plataforma' : 'Criar Conta Premium'}
            </button>
          </form>

          <div className="mt-8 flex flex-col items-center gap-4 relative z-10">
            <button onClick={() => setIsAuthMode(isAuthMode === 'login' ? 'register' : 'login')} className="text-sm text-gray-500 hover:text-purple-400 transition-colors">
              {isAuthMode === 'login' ? 'Não tem conta? Cadastre-se' : 'Já possui conta? Faça Login'}
            </button>

            <div className="w-full h-px bg-white/10 my-2"></div>

            <button 
              onClick={fillAdmin}
              className="flex items-center gap-2 px-4 py-2 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold hover:bg-red-500/20 transition-all"
            >
              <ShieldCheck size={14} />
              Preencher como Administrador
            </button>
          </div>
        </div>
      </div>
    );
  }

  const DashboardLayout = ({ children }: { children?: React.ReactNode }) => (
    <div className="min-h-screen bg-transparent text-white flex flex-col md:flex-row relative">
      {/* Toast System */}
      <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className="animate-slide-in glass px-6 py-3 rounded-2xl shadow-2xl border-l-4 border-purple-500 font-bold text-sm pointer-events-auto">
            {toast.message}
          </div>
        ))}
      </div>

      {/* Sidebar */}
      <aside className="w-full md:w-80 glass-card border-r border-white/5 p-8 space-y-10 overflow-y-auto flex flex-col">
        <div className="flex items-center gap-3">
          <div className="p-2.5 rounded-xl bg-gradient-primary shadow-xl">
            <Layers size={22} />
          </div>
          <h2 className="text-xl font-black tracking-tight text-gradient-primary">VITALÍCIO</h2>
        </div>

        <div className="p-5 rounded-3xl glass border border-white/10 space-y-4">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-2xl bg-gradient-primary flex items-center justify-center font-black text-xl shadow-lg">
              {currentUser.name[0]}
            </div>
            <div className="min-w-0">
              <p className="font-black text-sm truncate">{currentUser.name}</p>
              <p className="text-[10px] uppercase font-black text-purple-500 tracking-wider">
                {currentUser.isAdmin ? 'Administrador' : 'Membro Platinum'}
              </p>
            </div>
          </div>
          {!currentUser.isAdmin && (
            <div className="space-y-2">
              <div className="flex justify-between text-[10px] font-black text-gray-500 uppercase tracking-widest">
                <span>Nível de Maestria</span>
                <span className="text-purple-400">{userProgress}%</span>
              </div>
              <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden p-0.5">
                <div className="h-full bg-gradient-primary rounded-full shadow-[0_0_10px_rgba(168,85,247,0.5)] transition-all duration-1000" style={{ width: `${userProgress}%` }}></div>
              </div>
            </div>
          )}
        </div>

        <nav className="space-y-2">
          <p className="text-[10px] font-black text-gray-600 uppercase tracking-[3px] mb-4 ml-1">Explorar Trilhas</p>
          {['Todos', ...CATEGORIES].map(cat => {
            const IconComp = CATEGORY_ICONS[cat] || LayoutDashboard;
            return (
              <button key={cat} onClick={() => setActiveCategory(cat)}
                className={`w-full text-left px-5 py-3.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-4 group ${
                  activeCategory === cat ? 'bg-purple-600 text-white shadow-2xl scale-[1.02]' : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}>
                <IconComp size={18} className={activeCategory === cat ? 'text-white' : 'group-hover:text-purple-400 transition-colors'} />
                {cat}
              </button>
            );
          })}
        </nav>

        <button onClick={() => { setCurrentUser(null); setSelectedItem(null); setIsViewing(false); }}
          className="w-full mt-auto flex items-center justify-center gap-3 px-6 py-4 rounded-2xl bg-white/5 text-gray-500 font-bold hover:bg-red-500/10 hover:text-red-400 transition-all border border-transparent hover:border-red-500/20">
          <LogOut size={18} />
          Sair com Segurança
        </button>
      </aside>

      {/* Main content */}
      <main className="flex-1 overflow-y-auto bg-transparent scrollbar-hide">
