          <div className="flex-1 max-w-2xl relative">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
            <input type="text" placeholder="O que você deseja aprender hoje?" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-[2rem] pl-14 pr-6 py-4 text-sm outline-none focus:ring-2 focus:ring-purple-500/50 transition-all" />
          </div>
          <div className="flex items-center gap-6 ml-10">
            <div className="flex bg-white/5 p-1 rounded-2xl">
              <button onClick={() => setViewMode('grid')} className={`p-2.5 rounded-xl ${viewMode === 'grid' ? 'bg-purple-600 shadow-lg' : 'text-gray-500'}`}><Grid size={18}/></button>
              <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-xl ${viewMode === 'list' ? 'bg-purple-600 shadow-lg' : 'text-gray-500'}`}><List size={18}/></button>
