          <div className="p-2.5 rounded-xl bg-gradient-primary">
            <Layers size={22} />
          </div>
          <h2 className="text-xl font-black text-gradient-primary tracking-tighter">VITALÍCIO</h2>
        </div>

        <div className="p-6 rounded-3xl glass-card border border-white/10 space-y-4">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-gradient-primary flex items-center justify-center font-black text-xl shadow-lg">
                 {currentUser.name[0]}
