};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, 
  Search, 
  Grid, 
  List, 
  Book, 
  PlayCircle, 
  Plus, 
  Trash2, 
  Edit3, 
  LayoutDashboard,
  MessageSquare,
  Eye,
  CheckCircle,
  X,
  Send,
  ArrowRight,
  TrendingUp,
  Users,
  Bell,
  MoreVertical,
  Maximize2,
