  RotateCcw,
  Upload
} from 'lucide-react';
import { User, Material, MaterialType, CATEGORIES, CATEGORY_ICONS, Comment } from './types';
import { INITIAL_MATERIALS } from './constants';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  // Auth States
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);

  // App Content States
  const [items, setItems] = useState<Material[]>(() => {
    try {
      const saved = localStorage.getItem('vitalicio_materials');
      return saved ? JSON.parse(saved) : INITIAL_MATERIALS;
    } catch (e) {
      return INITIAL_MATERIALS;
    }
  });

  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  // Admin UI States
  const [isEditing, setIsEditing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '',
    type: 'curso',
    category: CATEGORIES[0],
    description: '',
    imageUrl: '',
  });

  const [toasts, setToasts] = useState<{id: string, message: string}[]>([]);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('vitalicio_materials', JSON.stringify(items));
  }, [items]);

  // Memoized Filtered Items
  const filteredItemsList = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           item.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const userProgress = useMemo(() => {
    if (!currentUser || items.length === 0) return 0;
    const readCount = items.filter(item => item.isReadBy.includes(currentUser.id)).length;
    return Math.round((readCount / items.length) * 100);
  }, [items, currentUser]);

  const stats = useMemo(() => ({
    total: items.length,
    views: items.reduce((acc, curr) => acc + curr.views, 0),
    comments: items.reduce((acc, curr) => acc + curr.comments.length, 0)
  }), [items]);

  const addToast = (message: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  };

  const handleGoogleLogin = () => {
    setIsGoogleLoading(true);
    setTimeout(() => {
      const googleUser: User = {
        id: 'google-' + Math.random().toString(36).substr(2, 9),
        name: 'Usuário Google',
        email: 'user@gmail.com',
        isAdmin: false
      };
      setCurrentUser(googleUser);
      setIsGoogleLoading(false);
      addToast("Conectado via Google! 🔐");
    }, 1200);
  };

  const fillAdmin = () => {
    const adminUser: User = { 
      id: 'admin-1', 
      name: 'Diretoria Vitalícia', 
      email: 'admin@academia.com', 
      isAdmin: true 
    };
    setCurrentUser(adminUser);
    addToast("Acesso administrativo concedido! 🛡️");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1.5 * 1024 * 1024) {
        addToast("Imagem muito pesada! Máximo 1.5MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setMaterialForm(prev => ({ ...prev, imageUrl: reader.result as string }));
        addToast("Preview da capa gerado!");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      fillAdmin();
    } else {
      setCurrentUser({ 
        id: Math.random().toString(36).substr(2, 9), 
        name: authName || 'Novo Aluno', 
        email: authEmail, 
        isAdmin: false 
      });
      addToast("Acesso Vitalício Liberado! 🚀");
    }
  };

  const handleAddOrUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) {
      addToast("Preencha título e imagem.");
      return;
    }

    if (isEditing && materialForm.id) {
      setItems(prev => prev.map(item => 
        item.id === materialForm.id ? { ...item, ...materialForm } as Material : item
      ));
      addToast("Material atualizado.");
    } else {
      const newItem: Material = {
        id: Math.random().toString(36).substr(2, 9),
        title: materialForm.title!,
        type: materialForm.type as MaterialType,
        category: materialForm.category!,
        description: materialForm.description || '',
        imageUrl: materialForm.imageUrl!,
        views: 0,
        comments: [],
        isReadBy: [],
        gradient: getRandomGradient()
      };
      setItems(prev => [newItem, ...prev]);
      addToast("Novo conteúdo publicado!");
    }
    setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '' });
    setIsEditing(false);
  };

  const toggleRead = (id: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const isRead = item.isReadBy.includes(currentUser.id);
        return {
          ...item,
          isReadBy: isRead 
            ? item.isReadBy.filter(uid => uid !== currentUser.id)
            : [...item.isReadBy, currentUser.id]
        };
      }
      return item;
    }));
  };

  const handleComment = (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      userName: currentUser.name,
      text: text,
      timestamp: new Date().toLocaleDateString('pt-BR')
    };
    setItems(prev => prev.map(item => 
      item.id === selectedItem.id 
        ? { ...item, comments: [newComment, ...item.comments] }
        : item
    ));
    setSelectedItem(prev => prev ? { ...prev, comments: [newComment, ...prev.comments] } : null);
    addToast("Insight compartilhado!");
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black relative overflow-hidden">
        <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl relative z-10 border border-white/10">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-black text-gradient-primary tracking-tighter mb-2">ACESSO VITALÍCIO</h1>
            <p className="text-gray-400 font-medium">Onde o conhecimento é eterno.</p>
          </div>

          <form onSubmit={handleAuth} className="space-y-4">
            {isAuthMode === 'register' && (
              <input type="text" placeholder="Seu Nome" value={authName} onChange={e => setAuthName(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            )}
            <input type="email" placeholder="Seu E-mail" value={authEmail} onChange={e => setAuthEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            <input type="password" placeholder="Sua Senha" value={authPassword} onChange={e => setAuthPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />

            <button type="submit" className="w-full py-4 rounded-2xl bg-gradient-primary text-white font-black text-sm uppercase tracking-widest hover:shadow-[0_0_30px_rgba(147,51,234,0.4)] transition-all transform hover:scale-[1.02] active:scale-95">
              {isAuthMode === 'login' ? 'Entrar Agora' : 'Finalizar Cadastro'}
            </button>
          </form>

          <div className="my-8 flex items-center gap-4 text-gray-600">
             <div className="flex-1 h-px bg-white/10"></div>
             <span className="text-[10px] font-black uppercase">Conexão Rápida</span>
             <div className="flex-1 h-px bg-white/10"></div>
          </div>

          <div className="space-y-4">
            <button onClick={handleGoogleLogin} disabled={isGoogleLoading}
              className="w-full py-4 rounded-2xl bg-white text-gray-900 font-bold text-sm flex items-center justify-center gap-3 hover:bg-gray-100 transition-all active:scale-95 disabled:opacity-50">
              {isGoogleLoading ? <div className="w-5 h-5 border-2 border-gray-300 border-t-gray-900 rounded-full animate-spin"></div> : (
                <>
                  <svg width="20" height="20" viewBox="0 0 48 48">
                    <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
                    <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
                    <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24s.92 7.54 2.56 10.78l7.97-6.19z"/>
                    <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.15 1.45-4.92 2.31-8.16 2.31-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
                  </svg>
                  Login via Google
                </>
              )}
            </button>

            <button 
              onClick={fillAdmin}
              className="w-full py-4 rounded-2xl bg-white/5 border border-white/10 text-gray-400 font-bold text-xs flex items-center justify-center gap-3 hover:bg-white/10 hover:text-white transition-all active:scale-95"
            >
              <ShieldCheck size={16} />
              Acesso Administrativo (Atalho)
            </button>
          </div>

          <div className="mt-8 text-center">
            <button onClick={() => setIsAuthMode(isAuthMode === 'login' ? 'register' : 'login')} className="text-xs text-gray-500 hover:text-purple-400 font-bold transition-colors">
              {isAuthMode === 'login' ? 'Não tem conta? Registre-se' : 'Já sou membro, fazer login'}
            </button>
          </div>
        </div>
      </div>
    );
  }

  const DashboardLayout = ({ children }: { children?: React.ReactNode }) => (
    <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
      <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className="animate-slide-in glass px-6 py-3 rounded-2xl shadow-2xl border-l-4 border-purple-500 font-bold text-sm pointer-events-auto">
            {toast.message}
          </div>
        ))}
      </div>

      {/* AJUSTADO: Sidebar mais estreita e com fundo mais visível */}
      <aside className="w-full md:w-64 lg:w-72 glass border-r border-white/10 p-6 flex flex-col gap-8 overflow-y-auto max-h-screen scrollbar-hide bg-[#050505]/80">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2.5 rounded-xl bg-gradient-primary shadow-lg shadow-purple-500/20">
            <Layers size={22} />
          </div>
          <h2 className="text-xl font-black text-gradient-primary tracking-tighter">VITALÍCIO</h2>
        </div>

        <div className="p-5 rounded-3xl glass-card border border-white/10 space-y-4 bg-white/[0.02]">
           <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-gradient-primary flex items-center justify-center font-black text-lg shadow-lg">
                 {currentUser.name[0]}
              </div>
              <div className="min-w-0">
                 <p className="font-black text-sm truncate">{currentUser.name}</p>
                 <p className="text-[10px] uppercase font-black text-purple-500/80">{currentUser.isAdmin ? 'Diretoria' : 'Membro Elite'}</p>
              </div>
           </div>
           {!currentUser.isAdmin && (
             <div className="space-y-2">
               <div className="flex justify-between text-[9px] font-black text-gray-500 uppercase tracking-widest">
                 <span>Progresso</span>
                 <span className="text-purple-400">{userProgress}%</span>
               </div>
               <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                 <div className="h-full bg-gradient-primary transition-all duration-1000 shadow-[0_0_10px_rgba(147,51,234,0.5)]" style={{ width: `${userProgress}%` }}></div>
               </div>
             </div>
           )}
        </div>

        <nav className="space-y-1">
          <p className="text-[10px] font-black text-gray-600 uppercase tracking-widest mb-3 ml-3">Categorias</p>
          {['Todos', ...CATEGORIES].map(cat => {
            const Icon = CATEGORY_ICONS[cat] || LayoutDashboard;
            return (
              <button key={cat} onClick={() => setActiveCategory(cat)}
                className={`w-full text-left px-4 py-3.5 rounded-2xl text-xs font-bold transition-all flex items-center gap-3 ${
                  activeCategory === cat ? 'bg-purple-600 text-white shadow-xl shadow-purple-900/20 scale-[1.02]' : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}>
                <Icon size={18} />
                {cat}
              </button>
            );
          })}
        </nav>

        <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }}
          className="w-full mt-auto flex items-center justify-center gap-3 px-6 py-4 rounded-2xl bg-white/5 text-gray-500 font-bold hover:bg-red-500/10 hover:text-red-400 transition-all border border-transparent hover:border-red-500/20">
          <LogOut size={18} />
          Sair
        </button>
      </aside>

      <main className="flex-1 overflow-y-auto scrollbar-hide bg-black">
        <header className="sticky top-0 z-40 px-6 md:px-10 py-5 glass border-b border-white/5 flex items-center justify-between bg-black/50 backdrop-blur-md">
           <div className="flex-1 max-w-xl relative">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input type="text" placeholder="Encontre seu próximo nível..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl pl-14 pr-6 py-3.5 text-sm outline-none focus:ring-2 focus:ring-purple-500/50 transition-all" />
           </div>
           <div className="flex items-center gap-4 ml-6">
              <div className="flex bg-white/5 p-1 rounded-xl border border-white/5">
                 <button onClick={() => setViewMode('grid')} className={`p-2 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-purple-600 text-white' : 'text-gray-500 hover:text-white'}`}><Grid size={18}/></button>
                 <button onClick={() => setViewMode('list')} className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-purple-600 text-white' : 'text-gray-500 hover:text-white'}`}><List size={18}/></button>
              </div>
           </div>
        </header>

        <div className="p-6 md:p-10 pb-32">
          {children}
        </div>
      </main>

      {/* Content Viewer Modal */}
      {selectedItem && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 overflow-hidden">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-3xl" onClick={() => setSelectedItem(null)}></div>
          <div className="relative w-full max-w-7xl h-full flex flex-col md:flex-row glass border border-white/10 rounded-[3rem] shadow-2xl overflow-hidden animate-slide-in">
            <div className="flex-1 flex flex-col overflow-y-auto p-10 bg-black">
               <div className="flex justify-between items-center mb-8">
                  <div className="flex items-center gap-4">
                    <div className={`p-4 rounded-2xl bg-gradient-to-br ${selectedItem.gradient}`}>
                       {selectedItem.type === 'curso' ? <PlayCircle size={28}/> : <Book size={28}/>}
                    </div>
                    <div>
                      <h2 className="text-3xl font-black">{selectedItem.title}</h2>
                      <p className="text-sm text-purple-400 font-bold uppercase tracking-widest">{selectedItem.category}</p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedItem(null)} className="p-3 bg-white/5 rounded-full hover:bg-white/10 transition-all"><X size={24}/></button>
               </div>
               <div className="aspect-video w-full rounded-[2.5rem] bg-gray-900 overflow-hidden mb-10 border border-white/5 relative group shadow-2xl">
                  <img src={selectedItem.imageUrl} className="w-full h-full object-cover opacity-50 group-hover:scale-105 transition-transform duration-[15s]" alt={selectedItem.title} />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <button className="p-8 rounded-full bg-white/10 backdrop-blur-xl border border-white/20 hover:scale-110 transition-all text-white">
                       {selectedItem.type === 'curso' ? <PlayCircle size={60} fill="white" /> : <Book size={60} fill="white" />}
                    </button>
                  </div>
               </div>
               <div className="max-w-4xl">
                  <h3 className="text-2xl font-black mb-6">Informações</h3>
                  <p className="text-gray-400 text-lg leading-relaxed mb-10">{selectedItem.description}</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                     <div className="glass p-6 rounded-3xl flex items-center gap-4 border border-white/5">
                        <Users size={24} className="text-purple-400" />
                        <div><p className="text-[10px] font-black uppercase text-gray-500">Visualizações</p><p className="font-bold text-xl">{selectedItem.views}</p></div>
                     </div>
                     <div className="glass p-6 rounded-3xl flex items-center gap-4 border border-white/5">
                        <TrendingUp size={24} className="text-pink-400" />
                        <div><p className="text-[10px] font-black uppercase text-gray-500">Qualidade</p><p className="font-bold text-xl">4K Ultra HD</p></div>
                     </div>
                     <div className="glass p-6 rounded-3xl flex items-center gap-4 border border-white/5">
                        <Maximize2 size={24} className="text-blue-400" />
                        <div><p className="text-[10px] font-black uppercase text-gray-500">Acesso</p><p className="font-bold text-xl">Vitalício</p></div>
                     </div>
                  </div>
               </div>
            </div>

            <div className="w-full md:w-[450px] bg-[#05070a] border-l border-white/5 flex flex-col">
               <div className="p-10 border-b border-white/5">
                  <h3 className="text-xl font-black flex items-center gap-3"><MessageSquare size={22} className="text-purple-500"/> Comentários</h3>
               </div>
               <div className="flex-1 overflow-y-auto p-10 space-y-8 scrollbar-hide">
                  {selectedItem.comments.length > 0 ? selectedItem.comments.map(c => (
                    <div key={c.id} className="space-y-3 animate-fade-in">
                       <div className="flex justify-between items-center">
                          <span className="text-sm font-black text-purple-400">{c.userName}</span>
                          <span className="text-[10px] text-gray-600 font-bold">{c.timestamp}</span>
                       </div>
                       <div className="p-5 rounded-[1.5rem] bg-white/[0.03] border border-white/5 text-sm text-gray-300 leading-relaxed">
                          {c.text}
                       </div>
                    </div>
                  )) : <div className="h-full flex flex-col items-center justify-center opacity-20 text-center"><MessageSquare size={48} className="mb-4"/><p className="font-bold">Ninguém comentou ainda.</p></div>}
               </div>
               <div className="p-10 border-t border-white/5">
                  <form className="relative" onSubmit={(e) => {
                    const input = (e.target as any).comment;
                    handleComment(e, input.value);
                    input.value = '';
                  }}>
                    <input name="comment" type="text" placeholder="Seu comentário..." className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-sm outline-none focus:ring-1 focus:ring-purple-500 pr-16" />
                    <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-gradient-primary rounded-xl"><Send size={20}/></button>
                  </form>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // Admin View
  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="space-y-12 animate-fade-in">
          <div className="flex items-center justify-between">
            <h1 className="text-4xl font-black tracking-tighter">Command Center</h1>
            <button onClick={() => { if(window.confirm('Resetar para o padrão?')) { setItems(INITIAL_MATERIALS); localStorage.removeItem('vitalicio_materials'); addToast('Resetado.'); } }} 
              className="flex items-center gap-2 px-6 py-3 rounded-2xl glass border border-orange-500/20 text-orange-500 text-xs font-black uppercase hover:bg-orange-500/10 transition-all"><RotateCcw size={16}/> Resetar Padrão</button>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
             <div className="xl:col-span-1 glass-card p-10 rounded-[3rem] border border-white/5 h-fit sticky top-10">
                <h3 className="text-2xl font-black mb-8 flex items-center gap-3">
                   {isEditing ? <Edit3 size={24} className="text-blue-500"/> : <Plus size={24} className="text-purple-500"/>}
                   {isEditing ? 'Editar Material' : 'Novo Lançamento'}
                </h3>
                <form onSubmit={handleAddOrUpdate} className="space-y-6">
                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Título do Card</p>
                      <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none" placeholder="Ex: Milionário com IA" />
                   </div>

                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Tipo</p>
                        <select value={materialForm.type} onChange={e => setMaterialForm({...materialForm, type: e.target.value as any})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none appearance-none">
                           <option value="curso">Vídeo</option>
                           <option value="ebook">E-book</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Categoria</p>
                        <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none appearance-none">
                           {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                   </div>

                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Capa do Material</p>
                      <div onClick={() => fileInputRef.current?.click()} className="w-full h-48 rounded-3xl border-2 border-dashed border-white/10 bg-white/5 flex flex-col items-center justify-center gap-4 cursor-pointer hover:bg-white/10 hover:border-purple-500/50 transition-all overflow-hidden relative group">
                         {materialForm.imageUrl ? (
                           <>
                            <img src={materialForm.imageUrl} className="w-full h-full object-cover" alt="preview" />
                            <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                               <p className="text-xs font-black uppercase text-white">Alterar Capa</p>
                            </div>
                           </>
                         ) : (
                           <>
                             <div className="p-4 rounded-full bg-purple-500/10 text-purple-500"><Upload size={24}/></div>
                             <p className="text-[11px] font-bold text-gray-400">Clique para upload (Máx 1.5MB)</p>
                           </>
                         )}
                         <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                      </div>
                   </div>

                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Descrição Curta</p>
                      <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none h-32 resize-none" placeholder="O que o aluno aprenderá?"></textarea>
                   </div>

                   <div className="flex gap-3">
                      <button type="submit" className="flex-1 py-5 bg-gradient-primary rounded-2xl font-black text-xs uppercase tracking-widest hover:shadow-2xl transition-all">
                        {isEditing ? 'Salvar Edição' : 'Publicar Conteúdo'}
                      </button>
                      {isEditing && (
                        <button type="button" onClick={() => { setIsEditing(false); setMaterialForm({title:'', type:'curso', category:CATEGORIES[0], description:'', imageUrl:''}); }} className="px-6 rounded-2xl bg-white/5 border border-white/10 font-black"><X/></button>
                      )}
                   </div>
                </form>
             </div>

             <div className="xl:col-span-2 space-y-6">
                <div className="glass-card rounded-[3rem] border border-white/5 overflow-hidden">
                   <div className="p-8 border-b border-white/5 flex justify-between items-center bg-white/5">
                      <h3 className="text-xl font-black">Inventário ({items.length})</h3>
                      <div className="flex gap-4">
                        <div className="flex items-center gap-2 text-xs font-bold text-gray-500"><Eye size={14}/> {stats.views}</div>
                        <div className="flex items-center gap-2 text-xs font-bold text-gray-500"><MessageSquare size={14}/> {stats.comments}</div>
                      </div>
                   </div>
                   <div className="divide-y divide-white/5 max-h-[800px] overflow-y-auto scrollbar-hide">
                      {items.map(item => (
                        <div key={item.id} className="p-8 flex items-center gap-6 hover:bg-white/[0.02] transition-colors group">
                           <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 border border-white/10 shadow-lg">
                              <img src={item.imageUrl} className="w-full h-full object-cover" alt={item.title} />
                           </div>
                           <div className="flex-1 min-w-0">
                              <h4 className="font-black text-lg truncate group-hover:text-purple-400 transition-colors">{item.title}</h4>
                              <p className="text-[10px] text-gray-500 font-bold uppercase mt-1">{item.type} &bull; {item.category}</p>
                           </div>
                           <div className="flex gap-2">
                              <button onClick={() => { setIsEditing(true); setMaterialForm(item); window.scrollTo({top: 0, behavior:'smooth'}); }} className="p-4 bg-blue-500/10 text-blue-400 rounded-2xl hover:bg-blue-500/20 transition-all"><Edit3 size={20}/></button>
                              <button onClick={() => { if(window.confirm('Excluir definitivamente?')) setItems(prev => prev.filter(i => i.id !== item.id)); }} className="p-4 bg-red-500/10 text-red-400 rounded-2xl hover:bg-red-500/20 transition-all"><Trash2 size={20}/></button>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-16 animate-fade-in">
        <section className="relative p-12 md:p-24 rounded-[4rem] overflow-hidden bg-gradient-to-br from-purple-800 via-pink-700 to-orange-600 shadow-2xl group">
           <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1464&auto=format&fit=crop')] bg-cover bg-center mix-blend-overlay opacity-20 group-hover:scale-105 transition-transform duration-[10s]"></div>
           <div className="relative z-10 max-w-2xl">
              <div className="inline-flex items-center gap-2 px-6 py-2 rounded-full glass border border-white/20 text-[10px] font-black uppercase tracking-[3px] mb-8">
                <Star size={14} fill="currentColor" /> Recomendado para você
              </div>
              <h1 className="text-5xl md:text-7xl lg:text-8xl font-black mb-8 leading-none tracking-tighter">
                Evolua seu <br/> <span className="text-black/30">Mindset.</span>
              </h1>
              <p className="text-lg md:text-xl text-white/80 font-medium mb-12 leading-relaxed italic">
                Sua jornada de evolução contínua começa hoje. Explore os códigos da maestria financeira e pessoal.
              </p>
              <div className="flex flex-wrap gap-6">
                 <button onClick={() => setActiveTab('curso')} className="px-12 py-5 rounded-2xl bg-white text-gray-950 font-black text-sm uppercase tracking-widest hover:shadow-2xl hover:scale-105 transition-all flex items-center gap-3 shadow-xl shadow-white/10">Explorar Trilhas <ArrowRight size={20}/></button>
              </div>
           </div>
        </section>

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-10">
           <div className="flex bg-white/5 p-2 rounded-[2.5rem] border border-white/10 w-fit">
              {(['todos', 'curso', 'ebook'] as const).map(tab => (
                <button key={tab} onClick={() => setActiveTab(tab)}
                  className={`px-8 md:px-12 py-3.5 rounded-[2rem] text-[10px] md:text-[11px] font-black uppercase tracking-widest transition-all ${
                    activeTab === tab ? 'bg-purple-600 shadow-2xl text-white scale-[1.05]' : 'text-gray-500 hover:text-white'
                  }`}>
                  {tab === 'todos' ? 'Biblioteca' : tab === 'curso' ? 'Cursos' : 'E-books'}
                </button>
              ))}
           </div>
           <div className="flex items-center gap-4 text-gray-500 font-black text-[10px] uppercase tracking-widest bg-white/5 px-6 py-3.5 rounded-full border border-white/5">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
              {filteredItemsList.length} Conteúdos Liberados
           </div>
        </div>

        {/* AJUSTADO: Grid agora tem 2 colunas em telas médias, 3 em grandes e 4 apenas em telas enormes */}
        <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-8 md:gap-10' : 'space-y-8'}>
          {filteredItemsList.map((item, index) => {
            const isRead = item.isReadBy.includes(currentUser.id);
            if (viewMode === 'grid') {
              return (
                <div key={item.id} className="group relative animate-fade-in" style={{ animationDelay: `${index * 50}ms` }}>
                   <div className={`absolute -inset-1 bg-gradient-to-r ${item.gradient} rounded-[3rem] opacity-0 group-hover:opacity-30 blur-2xl transition duration-500`}></div>
                   <div className="relative glass-card rounded-[3rem] border border-white/5 overflow-hidden h-full flex flex-col hover:border-white/20 transition-all duration-300">
                      <div className="relative h-60 md:h-64 overflow-hidden">
                         <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={item.title} />
                         <div className="absolute inset-0 bg-gradient-to-t from-black via-black/10 to-transparent"></div>
                         <div className="absolute top-6 left-6">
                            <span className="px-5 py-2 rounded-xl glass border border-white/10 text-[9px] font-black uppercase tracking-widest flex items-center gap-2 bg-black/30 backdrop-blur-md">
                               {item.type === 'curso' ? <PlayCircle size={14} className="text-purple-400"/> : <Book size={14} className="text-blue-400"/>}
                               {item.type}
                            </span>
                         </div>
                         {isRead && (
                           <div className="absolute top-6 right-6">
                              <div className="p-2.5 rounded-full bg-green-500 text-white shadow-[0_0_20px_#22C55E]">
                                 <CheckCircle size={18}/>
                              </div>
                           </div>
                         )}
                      </div>
                      <div className="p-8 md:p-10 pt-4 flex flex-col flex-1">
                         <h3 className="text-xl md:text-2xl font-black mb-4 leading-tight group-hover:text-purple-400 transition-colors line-clamp-1">{item.title}</h3>
                         <p className="text-gray-500 text-sm leading-relaxed line-clamp-2 mb-8 italic">"{item.description}"</p>

                         <div className="flex items-center justify-between mb-8 pb-6 border-b border-white/5 mt-auto">
                            <div className="flex gap-4">
                               <span className="text-[10px] font-black text-gray-500 flex items-center gap-1.5"><Eye size={12}/> {item.views}</span>
                               <span className="text-[10px] font-black text-gray-500 flex items-center gap-1.5"><MessageSquare size={12}/> {item.comments.length}</span>
                            </div>
                            <button onClick={(e) => { e.stopPropagation(); toggleRead(item.id); }} className={`p-2 transition-all ${isRead ? 'text-green-400' : 'text-gray-700 hover:text-white'}`}>
                               <CheckCircle size={24} fill={isRead ? 'currentColor' : 'none'} className={isRead ? 'fill-green-400/10' : ''}/>
                            </button>
                         </div>

                         <button onClick={() => setSelectedItem(item)} className={`w-full py-4.5 rounded-2xl font-black text-[10px] md:text-[11px] uppercase tracking-[3px] transition-all flex items-center justify-center gap-3 shadow-lg ${
                           item.type === 'curso' ? 'bg-purple-600/10 text-purple-400 hover:bg-purple-600 hover:text-white hover:shadow-purple-900/40' : 'bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white hover:shadow-blue-900/40'
                         }`}>Acessar <ArrowRight size={18}/></button>
                      </div>
                   </div>
                </div>
              );
            }
            return (
              <div key={item.id} className="glass-card p-8 rounded-[2.5rem] border border-white/5 flex flex-col md:flex-row items-center gap-10 group hover:bg-white/[0.03] transition-all animate-fade-in">
                 <div className="w-full md:w-56 h-36 rounded-3xl overflow-hidden flex-shrink-0 border border-white/10 shadow-2xl relative">
                    <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt={item.title} />
                    {isRead && <div className="absolute top-2 right-2 p-1.5 bg-green-500 text-white rounded-full shadow-lg"><CheckCircle size={14}/></div>}
                 </div>
                 <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-4 mb-3">
                       <h3 className="text-2xl font-black group-hover:text-purple-400 transition-colors">{item.title}</h3>
                       <span className="text-[9px] font-black uppercase text-purple-400 px-3 py-1 bg-purple-500/10 rounded-lg border border-purple-500/20">{item.category}</span>
                    </div>
                    <p className="text-gray-500 leading-relaxed italic line-clamp-1">{item.description}</p>
                 </div>
                 <div className="flex flex-col md:flex-row items-center gap-10">
                    <div className="flex gap-6">
                       <span className="text-[10px] font-black text-gray-600 flex items-center gap-1.5"><Eye size={14}/> {item.views}</span>
                       <span className="text-[10px] font-black text-gray-600 flex items-center gap-1.5"><MessageSquare size={14}/> {item.comments.length}</span>
                    </div>
                    <button onClick={() => setSelectedItem(item)} className="px-12 py-5 rounded-2xl bg-white/5 border border-white/10 font-black text-[11px] uppercase tracking-widest hover:bg-purple-600 hover:text-white hover:border-purple-600 transition-all">Começar</button>
                 </div>
              </div>
            );
          })}
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

{
  "name": "acesso-vitalicio",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "lucide-react": "^0.460.0"
  },
  "devDependencies": {
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "typescript": "^5.0.0",
    "vite": "^6.0.0"
  }
}

import { defineConfig } from 'vite';

export default defineConfig({
  root: './',
  build: {
    outDir: 'dist',
    minify: 'esbuild',
    sourcemap: false
  },
  server: {
    port: 3000
  }
});

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, 
  Search, 
  Grid, 
  List, 
  Book, 
  PlayCircle, 
  Plus, 
  Trash2, 
  Edit3, 
  LayoutDashboard,
  MessageSquare,
  Eye,
  CheckCircle,
  X,
  Send,
  ArrowRight,
  TrendingUp,
  Users,
  Bell,
  MoreVertical,
  Maximize2,
  Calendar,
  Layers,
  Star,
  ShieldCheck,
  RotateCcw,
  Upload
} from 'lucide-react';
import { User, Material, MaterialType, CATEGORIES, CATEGORY_ICONS, Comment } from './types';
import { INITIAL_MATERIALS } from './constants';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  // Auth States
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);

  // App Content States
  const [items, setItems] = useState<Material[]>(() => {
    try {
      const saved = localStorage.getItem('vitalicio_materials');
      return saved ? JSON.parse(saved) : INITIAL_MATERIALS;
    } catch (e) {
      return INITIAL_MATERIALS;
    }
  });

  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  // Admin UI States
  const [isEditing, setIsEditing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '',
    type: 'curso',
    category: CATEGORIES[0],
    description: '',
    imageUrl: '',
  });

  const [toasts, setToasts] = useState<{id: string, message: string}[]>([]);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('vitalicio_materials', JSON.stringify(items));
  }, [items]);

  // Memoized Filtered Items
  const filteredItemsList = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           item.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const userProgress = useMemo(() => {
    if (!currentUser || items.length === 0) return 0;
    const readCount = items.filter(item => item.isReadBy.includes(currentUser.id)).length;
    return Math.round((readCount / items.length) * 100);
  }, [items, currentUser]);

  const stats = useMemo(() => ({
    total: items.length,
    views: items.reduce((acc, curr) => acc + curr.views, 0),
    comments: items.reduce((acc, curr) => acc + curr.comments.length, 0)
  }), [items]);

  const addToast = (message: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  };

  const handleGoogleLogin = () => {
    setIsGoogleLoading(true);
    setTimeout(() => {
      const googleUser: User = {
        id: 'google-' + Math.random().toString(36).substr(2, 9),
        name: 'Usuário Google',
        email: 'user@gmail.com',
        isAdmin: false
      };
      setCurrentUser(googleUser);
      setIsGoogleLoading(false);
      addToast("Conectado via Google! 🔐");
    }, 1200);
  };

  const fillAdmin = () => {
    const adminUser: User = { 
      id: 'admin-1', 
      name: 'Diretoria Vitalícia', 
      email: 'admin@academia.com', 
      isAdmin: true 
    };
    setCurrentUser(adminUser);
    addToast("Acesso administrativo concedido! 🛡️");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1.5 * 1024 * 1024) {
        addToast("Imagem muito pesada! Máximo 1.5MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setMaterialForm(prev => ({ ...prev, imageUrl: reader.result as string }));
        addToast("Preview da capa gerado!");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      fillAdmin();
    } else {
      setCurrentUser({ 
        id: Math.random().toString(36).substr(2, 9), 
        name: authName || 'Novo Aluno', 
        email: authEmail, 
        isAdmin: false 
      });
      addToast("Acesso Vitalício Liberado! 🚀");
    }
  };

  const handleAddOrUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) {
      addToast("Preencha título e imagem.");
      return;
    }

    if (isEditing && materialForm.id) {
      setItems(prev => prev.map(item => 
        item.id === materialForm.id ? { ...item, ...materialForm } as Material : item
      ));
      addToast("Material atualizado.");
    } else {
      const newItem: Material = {
        id: Math.random().toString(36).substr(2, 9),
        title: materialForm.title!,
        type: materialForm.type as MaterialType,
        category: materialForm.category!,
        description: materialForm.description || '',
        imageUrl: materialForm.imageUrl!,
        views: 0,
        comments: [],
        isReadBy: [],
        gradient: getRandomGradient()
      };
      setItems(prev => [newItem, ...prev]);
      addToast("Novo conteúdo publicado!");
    }
    setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '' });
    setIsEditing(false);
  };

  const toggleRead = (id: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const isRead = item.isReadBy.includes(currentUser.id);
        return {
          ...item,
          isReadBy: isRead 
            ? item.isReadBy.filter(uid => uid !== currentUser.id)
            : [...item.isReadBy, currentUser.id]
        };
      }
      return item;
    }));
  };

  const handleComment = (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      userName: currentUser.name,
      text: text,
      timestamp: new Date().toLocaleDateString('pt-BR')
    };
    setItems(prev => prev.map(item => 
      item.id === selectedItem.id 
        ? { ...item, comments: [newComment, ...item.comments] }
        : item
    ));
    setSelectedItem(prev => prev ? { ...prev, comments: [newComment, ...prev.comments] } : null);
    addToast("Insight compartilhado!");
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black relative overflow-hidden">
        <div className="glass max-w-md w-full p-10 rounded-[2.5rem] shadow-2xl relative z-10 border border-white/10">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-black text-gradient-primary tracking-tighter mb-2">ACESSO VITALÍCIO</h1>
            <p className="text-gray-400 font-medium">Onde o conhecimento é eterno.</p>
          </div>

          <form onSubmit={handleAuth} className="space-y-4">
            {isAuthMode === 'register' && (
              <input type="text" placeholder="Seu Nome" value={authName} onChange={e => setAuthName(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            )}
            <input type="email" placeholder="Seu E-mail" value={authEmail} onChange={e => setAuthEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />
            <input type="password" placeholder="Sua Senha" value={authPassword} onChange={e => setAuthPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all" required />

            <button type="submit" className="w-full py-4 rounded-2xl bg-gradient-primary text-white font-black text-sm uppercase tracking-widest hover:shadow-[0_0_30px_rgba(147,51,234,0.4)] transition-all transform hover:scale-[1.02] active:scale-95">
              {isAuthMode === 'login' ? 'Entrar Agora' : 'Finalizar Cadastro'}
            </button>
          </form>

          <div className="my-8 flex items-center gap-4 text-gray-600">
             <div className="flex-1 h-px bg-white/10"></div>
             <span className="text-[10px] font-black uppercase">Conexão Rápida</span>
             <div className="flex-1 h-px bg-white/10"></div>
          </div>

          <div className="space-y-4">
            <button onClick={handleGoogleLogin} disabled={isGoogleLoading}
              className="w-full py-4 rounded-2xl bg-white text-gray-900 font-bold text-sm flex items-center justify-center gap-3 hover:bg-gray-100 transition-all active:scale-95 disabled:opacity-50">
              {isGoogleLoading ? <div className="w-5 h-5 border-2 border-gray-300 border-t-gray-900 rounded-full animate-spin"></div> : (
                <>
