// SUBSTITUA PELAS SUAS CHAVES DO PAINEL DO SUPABASE
const supabaseUrl = 'SUA_URL_AQUI';
const supabaseAnonKey = 'SUA_KEY_ANON_AQUI';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, TrendingUp, Users, Layers, Star, Upload, Link as LinkIcon, 
  ExternalLink, RotateCcw, Loader2
} from 'lucide-react';
import { User, Material, MaterialType, CATEGORIES, CATEGORY_ICONS, Comment } from './types';
