      const { data, error } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData: Material[] = data.map(m => ({
        id: m.id,
        title: m.title,
        type: m.type,
        category: m.category,
        description: m.description,
        imageUrl: m.image_url,
        videoUrl: m.video_url,
        views: m.views,
        gradient: m.gradient,
        // Map Supabase comments (snake_case) to match the Comment interface (camelCase)
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: [] // No futuro, vincular a uma tabela de progresso
      }));

      setItems(formattedData);
    } catch (e) {
      addToast("Erro ao carregar dados. Verifique a conexão.");
      console.error(e);
    } finally {
      setIsLoading(false);
