                  )) : <p className="text-center text-gray-600 font-bold py-10 uppercase text-[10px] tracking-widest">Nenhum insight compartilhado.</p>}
               </div>
               <div className="p-10 border-t border-white/5">
                  <form className="relative" onSubmit={(e) => {
                    const input = (e.target as any).comment;
                    handleComment(e, input.value);
                    input.value = '';
                  }}>
                    <input name="comment" type="text" placeholder="Deixe seu insight..." className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 text-sm outline-none focus:ring-1 focus:ring-purple-500 pr-16" />
                    <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-gradient-primary rounded-xl"><Send size={20}/></button>
                  </form>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="space-y-12 animate-fade-in">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
