                </h3>
                <form onSubmit={handleAddOrUpdate} className="space-y-6">
                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Título do Material</p>
                      <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none" placeholder="Ex: Masterclass Finanças" />
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Tipo</p>
                        <select value={materialForm.type} onChange={e => setMaterialForm({...materialForm, type: e.target.value as any})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none appearance-none">
                           <option value="curso">Vídeo Aula</option>
                           <option value="ebook">Livro Digital</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Categoria</p>
                        <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none appearance-none">
                           {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                   </div>
                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">URL da Imagem de Capa</p>
                      <input type="text" value={materialForm.imageUrl} onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none" placeholder="https://..." />
                   </div>
                   <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">URL do Conteúdo (Link)</p>
                      <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm outline-none" placeholder="https://..." />
                   </div>
