                      <p className="text-[10px] font-black uppercase text-gray-500 ml-2">Descrição Curta</p>
                      <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-sm h-32 resize-none outline-none"></textarea>
