                        <button type="button" onClick={() => { setIsEditing(false); setMaterialForm({title:'', type:'curso', category:CATEGORIES[0], description:'', imageUrl:'', videoUrl:''}); }} className="px-6 rounded-2xl bg-white/5 border border-white/10 font-black"><X/></button>
