                              <button onClick={() => { setIsEditing(true); setMaterialForm(item); window.scrollTo({top: 0, behavior:'smooth'}); }} className="p-5 bg-blue-500/5 text-blue-400 rounded-2xl hover:bg-blue-500/20 transition-all border border-blue-500/10 shadow-lg"><Edit3 size={20}/></button>
