                  activeCategory === cat ? 'bg-purple-600 text-white shadow-xl translate-x-1' : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}>
                <Icon size={18} /> {cat}
              </button>
            );
          })}
        </nav>

        <div className="mt-auto space-y-4">
           <div className={`flex items-center gap-2 px-4 py-3 rounded-xl border border-white/5 text-[9px] font-black uppercase tracking-wider ${
             dbStatus === 'connected' ? 'text-green-500 bg-green-500/5' : 'text-red-500 bg-red-500/5'
           }`}>
             <div className={`w-2 h-2 rounded-full animate-pulse ${dbStatus === 'connected' ? 'bg-green-500' : 'bg-red-500'}`}></div>
             Sincronizado: VPS Ativa
           </div>
           <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }}
