           <div className="flex items-center gap-5 ml-8">
              <button onClick={() => fetchData()} className="p-3.5 bg-white/5 rounded-xl hover:bg-white/10 text-gray-500 hover:text-white transition-all border border-white/5 group">
                <RotateCcw size={18} className="group-active:rotate-180 transition-transform duration-500" />
              </button>
              <div className="flex bg-white/5 p-1.5 rounded-xl border border-white/5 gap-1">
                 <button onClick={() => setViewMode('grid')} className={`p-2.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}><Grid size={18}/></button>
                 <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-lg transition-all ${viewMode === 'list' ? 'bg-purple-600 text-white shadow-lg' : 'text-gray-600 hover:text-gray-400'}`}><List size={18}/></button>
