                         <div className="space-y-3">
                            <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px] ml-4 flex items-center gap-2"><Info size={12}/> Título</label>
                            <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-3xl px-8 py-5 text-sm outline-none transition-all focus:ring-1 focus:ring-purple-500" placeholder="Título do material" />
