                               <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'curso'})} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase transition-all ${materialForm.type === 'curso' ? 'bg-purple-600 text-white' : 'text-gray-500 hover:text-white'}`}>Vídeo</button>
                               <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'ebook'})} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase transition-all ${materialForm.type === 'ebook' ? 'bg-blue-600 text-white' : 'text-gray-500 hover:text-white'}`}>E-book</button>
                            </div>
                         </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px] ml-4">Categoria</label>
                        <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-3xl px-8 py-5 text-sm outline-none appearance-none font-bold">
                           {CATEGORIES.map(c => <option key={c} value={c} className="bg-black">{c}</option>)}
                        </select>
                      </div>

                      {/* UPLOAD CAPA */}
                      <div className="space-y-5 p-8 rounded-[3rem] bg-white/[0.02] border border-white/5">
                        <div className="flex justify-between items-center">
                           <label className="text-[10px] font-black uppercase text-gray-400 tracking-[3px] flex items-center gap-2"><ImageIcon size={14}/> Imagem de Capa</label>
                           <button type="button" onClick={() => fileInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-purple-500/10 text-purple-400 rounded-xl hover:bg-purple-500 hover:text-white transition-all">
                             {isUploading === 'image' ? <Loader2 size={12} className="animate-spin"/> : 'Fazer Upload'}
                           </button>
                        </div>
                        <input type="text" value={materialForm.imageUrl} onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})} className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-xs outline-none" placeholder="Link da imagem..." />
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'image')} />
                        {materialForm.imageUrl && <img src={materialForm.imageUrl} className="mt-4 rounded-2xl aspect-video object-cover border border-white/10" alt="Preview" />}
                      </div>

                      {/* UPLOAD CONTEÚDO */}
                      <div className="space-y-5 p-8 rounded-[3rem] bg-white/[0.02] border border-white/5">
                        <div className="flex justify-between items-center">
                           <label className="text-[10px] font-black uppercase text-gray-400 tracking-[3px] flex items-center gap-2">
                             {materialForm.type === 'curso' ? <PlayCircle size={14}/> : <FileText size={14}/>} {materialForm.type === 'curso' ? 'Arquivo Vídeo' : 'Arquivo PDF'}
                           </label>
                           <button type="button" onClick={() => contentInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-blue-500/10 text-blue-400 rounded-xl hover:bg-blue-500 hover:text-white transition-all">
                             {isUploading === 'content' ? <Loader2 size={12} className="animate-spin"/> : 'Fazer Upload'}
                           </button>
                        </div>
                        <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-xs outline-none" placeholder="Link do conteúdo..." />
                        <input type="file" ref={contentInputRef} className="hidden" accept={materialForm.type === 'curso' ? "video/*" : "application/pdf"} onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'content')} />
                      </div>

                      <div className="space-y-3">
                         <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px] ml-4">Descrição</label>
                         <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-[2.5rem] px-8 py-6 text-sm h-32 resize-none outline-none focus:ring-1 focus:ring-purple-500 transition-all"></textarea>
                      </div>

                      <button type="submit" disabled={isUploading !== 'none'} className="w-full py-7 bg-gradient-primary rounded-[2.5rem] font-black text-xs uppercase tracking-[5px] hover:shadow-[0_20px_50px_rgba(147,51,234,0.3)] transition-all transform active:scale-95 disabled:opacity-50">
                        {isEditing ? 'Salvar Alterações' : 'Publicar Agora na VPS'}
                      </button>
                   </form>
                </div>
             </div>

             {/* LISTA */}
             <div className="xl:col-span-7">
                <div className="glass-card rounded-[4rem] border border-white/10 overflow-hidden shadow-2xl">
                   <div className="p-12 border-b border-white/10 bg-white/5 flex justify-between items-center">
