import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, UploadCloud, Link as LinkIcon, FileText, Image as ImageIcon,
  Check, Info
} from 'lucide-react';
import { User, Material, CATEGORIES, CATEGORY_ICONS } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);

  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    let displayMessage = typeof message === 'string' ? message : (message?.message || "Ocorreu um erro");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 6000);
  };

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData: Material[] = (data || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type,
        category: m.category,
        description: m.description,
        imageUrl: m.image_url,
        videoUrl: m.video_url,
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      addToast("Erro ao sincronizar com a VPS. Verifique a tabela 'materials'.", 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleFileUpload = async (file: File, type: 'image' | 'content') => {
    if (!file) return;

    // Validar tamanho (Max 50MB para VPS padrão)
    if (file.size > 50 * 1024 * 1024) {
      return addToast("Arquivo muito grande. Limite de 50MB.", "error");
    }

    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { data: uploadData, error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file, {
          cacheControl: '3600',
          upsert: false
        });

      if (uploadError) {
        console.error("Erro detalhado do Supabase:", uploadError);
        throw new Error(uploadError.message);
      }

      const { data } = supabase.storage
        .from('materials')
        .getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa carregada com sucesso! ✨");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Arquivo de conteúdo enviado para a VPS! 🚀");
      }
    } catch (e: any) {
      console.error("Erro no Upload:", e);
      addToast(`Falha no Upload: ${e.message}. Verifique as Políticas RLS no Supabase.`, 'error');
    } finally {
      setIsUploading('none');
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin', name: 'Diretoria Vitalício', email: authEmail, isAdmin: true });
      addToast("Painel de Controle Admin Liberado! 🛡️");
    } else {
      setCurrentUser({ id: 'user-' + Date.now(), name: authName || 'Membro Elite', email: authEmail, isAdmin: false });
      addToast(`Bem-vindo à Ordem Vitalícia, ${authName || 'Membro'}! 🚀`);
    }
  };

  const handleAddOrUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title) return addToast("Defina um título para o módulo.", 'error');
    if (!materialForm.imageUrl) return addToast("É necessário uma imagem de capa.", 'error');
    if (!materialForm.videoUrl) return addToast("Insira o link ou faça upload do conteúdo.", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      if (isEditing && materialForm.id) {
        const { error } = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        if (error) throw error;
        addToast("Módulo atualizado com sucesso!");
      } else {
        const { error } = await supabase.from('materials').insert([payload]);
        if (error) throw error;
        addToast("Novo conteúdo publicado na plataforma!");
      }
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao salvar: Verifique se as colunas da tabela estão corretas.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Isso removerá o conteúdo permanentemente. Deseja continuar?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Conteúdo removido da VPS.");
      fetchData();
    } catch (e: any) {
      addToast(e, 'error');
    }
  };

  const handleComment = async (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;

    try {
      const { error } = await supabase.from('comments').insert([{
        material_id: selectedItem.id,
        user_name: currentUser.name,
        text: text,
        timestamp: new Date().toLocaleDateString('pt-BR')
      }]);
      if (error) throw error;

      const { data: newComments } = await supabase.from('comments').select('*').eq('material_id', selectedItem.id);
      const formattedComments = (newComments || []).map((c: any) => ({
        id: c.id, userName: c.user_name, text: c.text, timestamp: c.timestamp
      }));

      setSelectedItem({...selectedItem, comments: formattedComments});
      fetchData();
    } catch (e: any) {
      addToast(e, 'error');
    }
  };

  const filteredItemsList = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = (item.title || "").toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const DashboardLayout = ({ children }: { children?: React.ReactNode }) => (
    <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
      <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`animate-slide-in glass px-6 py-4 rounded-2xl shadow-2xl border-l-4 font-bold text-xs pointer-events-auto max-w-xs flex items-center gap-3 ${
            toast.type === 'error' ? 'border-red-500 bg-red-500/5' : 'border-purple-500'
          }`}>
            {toast.type === 'error' ? <AlertCircle size={18} className="text-red-400" /> : <CheckCircle size={18} className="text-purple-400" />}
            {toast.message}
          </div>
        ))}
      </div>

      <aside className="w-full md:w-64 lg:w-72 glass border-r border-white/10 p-6 flex flex-col gap-8 overflow-y-auto max-h-screen scrollbar-hide bg-[#050505]/90 backdrop-blur-3xl">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2.5 rounded-xl bg-gradient-primary shadow-xl">
            <Layers size={22} />
          </div>
          <h2 className="text-2xl font-black text-gradient-primary tracking-tighter">VITALÍCIO</h2>
        </div>

        <div className="p-5 rounded-3xl glass-card border border-white/10 space-y-4">
           <div className="flex items-center gap-4">
              <div className="w-11 h-11 rounded-2xl bg-gradient-primary flex items-center justify-center font-black text-xl shadow-lg">
                 {currentUser?.name[0]}
              </div>
              <div className="min-w-0">
                 <p className="font-black text-sm truncate">{currentUser?.name}</p>
                 <p className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-md w-fit ${currentUser?.isAdmin ? 'bg-purple-500/20 text-purple-400' : 'bg-white/10 text-gray-500'}`}>
                   {currentUser?.isAdmin ? 'ADMINISTRADOR' : 'MEMBRO ELITE'}
                 </p>
              </div>
           </div>
        </div>

        <nav className="space-y-1.5">
          <p className="text-[10px] font-black text-gray-600 uppercase tracking-[3px] mb-4 ml-4">Módulos</p>
          {['Todos', ...CATEGORIES].map(cat => {
            const Icon = CATEGORY_ICONS[cat] || LayoutDashboard;
            return (
              <button key={cat} onClick={() => setActiveCategory(cat)}
                className={`w-full text-left px-5 py-4 rounded-2xl text-xs font-bold transition-all flex items-center gap-4 ${
                  activeCategory === cat ? 'bg-purple-600 text-white shadow-xl translate-x-1' : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}>
                <Icon size={18} /> {cat}
              </button>
            );
          })}
        </nav>

        <div className="mt-auto space-y-4">
           <div className={`flex items-center gap-2 px-4 py-3 rounded-xl border border-white/5 text-[9px] font-black uppercase tracking-wider ${
             dbStatus === 'connected' ? 'text-green-500 bg-green-500/5' : 'text-red-500 bg-red-500/5'
           }`}>
             <div className={`w-2 h-2 rounded-full animate-pulse ${dbStatus === 'connected' ? 'bg-green-500' : 'bg-red-500'}`}></div>
             Conexão: VPS Estável
           </div>
           <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }}
             className="w-full flex items-center justify-center gap-3 px-6 py-4.5 rounded-2xl bg-white/5 text-gray-500 font-bold hover:bg-red-500/10 hover:text-red-400 transition-all border border-transparent hover:border-red-500/20">
             <LogOut size={18} /> Logout Seguro
