                           <button type="button" onClick={() => contentInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-blue-500/10 text-blue-400 rounded-xl hover:bg-blue-500 hover:text-white transition-all">
                             {isUploading === 'content' ? <Loader2 size={12} className="animate-spin"/> : 'Fazer Upload'}
                           </button>
                        </div>
                        <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-xs outline-none" placeholder="Link do conteúdo..." />
                        <input type="file" ref={contentInputRef} className="hidden" accept={materialForm.type === 'curso' ? "video/*" : "application/pdf"} onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'content')} />
                      </div>

                      <div className="space-y-3">
                         <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px] ml-4">Descrição</label>
                         <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-[2.5rem] px-8 py-6 text-sm h-32 resize-none outline-none focus:ring-1 focus:ring-purple-500 transition-all"></textarea>
                      </div>

                      <button type="submit" disabled={isUploading !== 'none'} className="w-full py-7 bg-gradient-primary rounded-[2.5rem] font-black text-xs uppercase tracking-[5px] transition-all transform active:scale-95 disabled:opacity-50">
                        {isEditing ? 'Salvar Alterações' : 'Publicar na VPS'}
                      </button>
                   </form>
                </div>
             </div>

             <div className="xl:col-span-7">
                <div className="glass-card rounded-[4rem] border border-white/10 overflow-hidden shadow-2xl">
                   <div className="p-12 border-b border-white/10 bg-white/5 flex justify-between items-center">
                      <h3 className="text-xl font-black uppercase tracking-[4px] text-gray-400">Biblioteca VPS</h3>
                      <span className="px-6 py-2 rounded-full bg-purple-500/10 text-purple-400 font-black text-[10px] uppercase border border-purple-500/20">{items.length} Ativos</span>
                   </div>
                   <div className="divide-y divide-white/5 max-h-[1000px] overflow-y-auto scrollbar-hide">
                      {items.map(item => (
                        <div key={item.id} className="p-10 flex items-center gap-10 hover:bg-white/[0.02] transition-colors group">
                           <img src={item.imageUrl} className="w-24 h-24 rounded-3xl object-cover border border-white/10 shadow-xl" alt={item.title} />
                           <div className="flex-1 min-w-0">
                              <h4 className="font-black text-2xl truncate group-hover:text-purple-400 transition-colors mb-2 tracking-tighter">{item.title}</h4>
                              <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">{item.category} • {item.type}</p>
                           </div>
                           <div className="flex gap-4">
                              <button onClick={() => { setIsEditing(true); setMaterialForm(item); window.scrollTo({top:0, behavior:'smooth'}); }} className="p-5 bg-blue-500/5 text-blue-400 rounded-2xl hover:bg-blue-500/20 transition-all border border-blue-500/10"><Edit3 size={20}/></button>
                              <button onClick={() => handleDelete(item.id)} className="p-5 bg-red-500/5 text-red-400 rounded-2xl hover:bg-red-500/20 transition-all border border-red-500/10"><Trash2 size={20}/></button>
                           </div>
                        </div>
                      ))}
                      {items.length === 0 && <div className="p-40 text-center text-gray-600 font-black uppercase tracking-[8px] text-sm">Vazio</div>}
                   </div>
                </div>
             </div>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-20 animate-fade-in">
        <section className="relative p-16 md:p-28 rounded-[5rem] overflow-hidden shadow-2xl group">
           <div className={`absolute inset-0 bg-gradient-to-br from-purple-900 via-purple-700 to-pink-600 opacity-90 transition-all duration-1000 group-hover:scale-105`}></div>
           <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1634017839464-5c339ebe3cb4?q=80&w=1470&auto=format&fit=crop')] bg-cover bg-center mix-blend-overlay opacity-30"></div>
           <div className="relative z-10 max-w-3xl">
              <div className="inline-flex items-center gap-3 px-8 py-3 rounded-full glass border border-white/20 text-[10px] font-black uppercase tracking-[4px] mb-12 shadow-2xl">
                <Star size={16} fill="currentColor" className="text-yellow-400" /> Membro Vitalício Oficial
              </div>
              <h1 className="text-6xl md:text-8xl lg:text-9xl font-black mb-10 leading-none tracking-tighter text-white">
                Seu Futuro <br/> <span className="text-black/30">Começa Aqui.</span>
              </h1>
              <p className="text-xl md:text-2xl text-white/80 font-medium mb-16 leading-relaxed italic max-w-2xl">
                Toda a sua biblioteca de conhecimentos premium, hospedada com segurança no seu Easypanel.
              </p>
              <button onClick={() => setActiveTab('curso')} className="px-16 py-6 rounded-[2rem] bg-white text-black font-black text-xs uppercase tracking-[4px] hover:shadow-[0_20px_60px_rgba(255,255,255,0.2)] hover:scale-105 transition-all flex items-center gap-4 active:scale-95 shadow-2xl">
                Abrir Biblioteca <ArrowRight size={22}/>
              </button>
           </div>
        </section>

        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-12">
           <div className="flex bg-white/5 p-2.5 rounded-[3rem] border border-white/10 w-fit backdrop-blur-xl shadow-2xl">
              {(['todos', 'curso', 'ebook'] as const).map(tab => (
                <button key={tab} onClick={() => setActiveTab(tab)}
                  className={`px-10 md:px-16 py-5 rounded-[2.5rem] text-[10px] md:text-[11px] font-black uppercase tracking-[3px] transition-all duration-500 ${
                    activeTab === tab ? 'bg-purple-600 shadow-[0_10px_30px_rgba(147,51,234,0.4)] text-white scale-[1.05]' : 'text-gray-500 hover:text-white'
                  }`}>
                  {tab === 'todos' ? 'Ver Tudo' : tab === 'curso' ? 'Vídeos' : 'E-books'}
                </button>
              ))}
           </div>
        </div>

        <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-10 md:gap-14' : 'space-y-12'}>
          {filteredItemsList.map((item, index) => (
            <div key={item.id} className="group relative animate-fade-in" style={{ animationDelay: `${index * 60}ms` }}>
               <div className={`absolute -inset-2 bg-gradient-to-r ${item.gradient} rounded-[4rem] opacity-0 group-hover:opacity-40 blur-3xl transition-all duration-700`}></div>
               <div className="relative glass-card rounded-[4rem] border border-white/5 overflow-hidden h-full flex flex-col hover:border-purple-500/30 transition-all duration-500 shadow-2xl hover:-translate-y-3">
                  <div className="relative h-72 md:h-80 overflow-hidden">
                     <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1.5s]" alt={item.title} />
                     <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent"></div>
                     <div className="absolute top-8 left-8">
                        <span className="px-6 py-2.5 rounded-2xl glass border border-white/10 text-[9px] font-black uppercase tracking-[3px] flex items-center gap-3 bg-black/40 backdrop-blur-2xl shadow-xl">
                           {item.type === 'curso' ? <PlayCircle size={14} className="text-purple-400"/> : <Book size={14} className="text-blue-400"/>}
                           {item.type}
                        </span>
                     </div>
                  </div>
                  <div className="p-10 md:p-12 pt-6 flex flex-col flex-1">
                     <h3 className="text-2xl md:text-3xl font-black mb-6 leading-tight group-hover:text-purple-400 transition-colors line-clamp-2 tracking-tighter">{item.title}</h3>
                     <p className="text-gray-500 text-base leading-relaxed line-clamp-2 mb-10 italic font-medium opacity-80">"{item.description}"</p>

                     <div className="flex items-center justify-between mb-10 pb-8 border-b border-white/5 mt-auto">
                        <div className="flex gap-6">
                           <span className="text-[10px] font-black text-gray-500 flex items-center gap-2 tracking-widest"><Eye size={14}/> {item.views.toLocaleString()}</span>
                           <span className="text-[10px] font-black text-gray-500 flex items-center gap-2 tracking-widest"><MessageSquare size={14}/> {(item.comments || []).length}</span>
                        </div>
                        <CheckCircle size={22} className="text-purple-900 group-hover:text-purple-500 transition-colors" strokeWidth={2.5} />
                     </div>
                     <button onClick={() => setSelectedItem(item)} className="w-full py-5 rounded-[2rem] font-black text-[10px] md:text-[11px] uppercase tracking-[4px] transition-all flex items-center justify-center gap-4 shadow-2xl bg-purple-600/10 text-purple-400 hover:bg-purple-600 hover:text-white border border-purple-500/20 active:scale-95">
                        Acessar Portal <ArrowRight size={20}/>
                     </button>
                  </div>
               </div>
            </div>
          ))}
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, UploadCloud, Link as LinkIcon, FileText, Image as ImageIcon,
  Check, Info
} from 'lucide-react';
import { User, Material, CATEGORIES, CATEGORY_ICONS } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);

  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    let displayMessage = typeof message === 'string' ? message : (message?.message || "Erro desconhecido");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 6000);
  };

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData: Material[] = (data || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type,
        category: m.category,
        description: m.description,
        imageUrl: m.image_url,
        videoUrl: m.video_url,
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      addToast("Erro na VPS: Verifique se a tabela 'materials' existe.", 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleFileUpload = async (file: File, type: 'image' | 'content') => {
    if (!file) return;

    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) {
        if (uploadError.message.includes('Bucket not found')) {
          throw new Error("Balde (Bucket) 'materials' não encontrado no Storage do Supabase. Crie-o primeiro!");
        }
        throw uploadError;
      }

      const { data } = supabase.storage
        .from('materials')
        .getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa carregada com sucesso!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Arquivo salvo na VPS!");
      }
    } catch (e: any) {
      console.error("Erro no Storage:", e);
      addToast(e.message, 'error');
    } finally {
      setIsUploading('none');
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin', name: 'Diretoria Vitalício', email: authEmail, isAdmin: true });
      addToast("Portal Admin Liberado!");
    } else {
      setCurrentUser({ id: 'user-' + Date.now(), name: authName || 'Membro Elite', email: authEmail, isAdmin: false });
      addToast(`Bem-vindo, ${authName || 'Membro'}!`);
    }
  };

  const handleAddOrUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return addToast("Preencha o título e a capa.", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      if (isEditing && materialForm.id) {
        const { error } = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        if (error) throw error;
        addToast("Módulo atualizado!");
      } else {
        const { error } = await supabase.from('materials').insert([payload]);
        if (error) throw error;
        addToast("Publicado com sucesso!");
      }
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao salvar no banco. Verifique as colunas.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Confirmar exclusão?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Removido.");
      fetchData();
    } catch (e: any) {
      addToast("Erro ao deletar.", 'error');
    }
  };

  const handleComment = async (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;

    try {
      const { error } = await supabase.from('comments').insert([{
        material_id: selectedItem.id,
        user_name: currentUser.name,
        text: text,
        timestamp: new Date().toLocaleDateString('pt-BR')
      }]);
      if (error) throw error;
      fetchData();
    } catch (e: any) {
      addToast("Erro ao enviar comentário.", 'error');
    }
  };

  const filteredItemsList = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = (item.title || "").toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  const DashboardLayout = ({ children }: { children?: React.ReactNode }) => (
    <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
      <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`animate-slide-in glass px-6 py-4 rounded-2xl shadow-2xl border-l-4 font-bold text-xs pointer-events-auto max-w-xs flex items-center gap-3 ${
            toast.type === 'error' ? 'border-red-500 bg-red-500/5' : 'border-purple-500'
          }`}>
            {toast.type === 'error' ? <AlertCircle size={18} className="text-red-400" /> : <CheckCircle size={18} className="text-purple-400" />}
            {toast.message}
          </div>
        ))}
      </div>

      <aside className="w-full md:w-64 lg:w-72 glass border-r border-white/10 p-6 flex flex-col gap-8 overflow-y-auto max-h-screen scrollbar-hide bg-[#050505]/90 backdrop-blur-3xl">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2.5 rounded-xl bg-gradient-primary shadow-xl">
            <Layers size={22} />
          </div>
          <h2 className="text-2xl font-black text-gradient-primary tracking-tighter">VITALÍCIO</h2>
        </div>

        <div className="p-5 rounded-3xl glass-card border border-white/10 space-y-4">
           <div className="flex items-center gap-4">
              <div className="w-11 h-11 rounded-2xl bg-gradient-primary flex items-center justify-center font-black text-xl shadow-lg">
                 {currentUser?.name[0]}
              </div>
              <div className="min-w-0">
                 <p className="font-black text-sm truncate">{currentUser?.name}</p>
                 <p className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-md w-fit ${currentUser?.isAdmin ? 'bg-purple-500/20 text-purple-400' : 'bg-white/10 text-gray-500'}`}>
                   {currentUser?.isAdmin ? 'ADMINISTRADOR' : 'MEMBRO ELITE'}
                 </p>
              </div>
           </div>
        </div>

        <nav className="space-y-1.5">
          <p className="text-[10px] font-black text-gray-600 uppercase tracking-[3px] mb-4 ml-4">Módulos</p>
          {['Todos', ...CATEGORIES].map(cat => {
            const Icon = CATEGORY_ICONS[cat] || LayoutDashboard;
            return (
              <button key={cat} onClick={() => setActiveCategory(cat)}
                className={`w-full text-left px-5 py-4 rounded-2xl text-xs font-bold transition-all flex items-center gap-4 ${
                  activeCategory === cat ? 'bg-purple-600 text-white shadow-xl translate-x-1' : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}>
                <Icon size={18} /> {cat}
              </button>
            );
          })}
        </nav>

        <div className="mt-auto space-y-4">
           <div className={`flex items-center gap-2 px-4 py-3 rounded-xl border border-white/5 text-[9px] font-black uppercase tracking-wider ${
             dbStatus === 'connected' ? 'text-green-500 bg-green-500/5' : 'text-red-500 bg-red-500/5'
           }`}>
             <div className={`w-2 h-2 rounded-full animate-pulse ${dbStatus === 'connected' ? 'bg-green-500' : 'bg-red-500'}`}></div>
             Sincronizado
           </div>
           <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }}
             className="w-full flex items-center justify-center gap-3 px-6 py-4.5 rounded-2xl bg-white/5 text-gray-500 font-bold hover:bg-red-500/10 hover:text-red-400 transition-all border border-transparent hover:border-red-500/20">
             <LogOut size={18} /> Sair
           </button>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto scrollbar-hide bg-black">
        <header className="sticky top-0 z-40 px-6 md:px-10 py-6 glass border-b border-white/5 flex items-center justify-between bg-black/60 backdrop-blur-2xl">
           <div className="flex-1 max-w-xl relative">
              <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input type="text" placeholder="Buscar módulos..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl pl-16 pr-8 py-4 text-sm outline-none focus:ring-2 focus:ring-purple-500/40 transition-all placeholder:text-gray-600" />
           </div>
           <div className="flex items-center gap-5 ml-8">
              <button onClick={() => fetchData()} className="p-3.5 bg-white/5 rounded-xl hover:bg-white/10 text-gray-500 hover:text-white transition-all border border-white/5 group">
                <RotateCcw size={18}/>
              </button>
              <div className="flex bg-white/5 p-1.5 rounded-xl border border-white/5 gap-1">
                 <button onClick={() => setViewMode('grid')} className={`p-2.5 rounded-lg ${viewMode === 'grid' ? 'bg-purple-600 text-white' : 'text-gray-600'}`}><Grid size={18}/></button>
                 <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-lg ${viewMode === 'list' ? 'bg-purple-600 text-white' : 'text-gray-600'}`}><List size={18}/></button>
              </div>
           </div>
        </header>
        <div className="p-6 md:p-12 pb-32">{children}</div>
      </main>

      {selectedItem && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 md:p-8 animate-fade-in">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-3xl" onClick={() => setSelectedItem(null)}></div>
          <div className="relative w-full max-w-7xl h-full max-h-[92vh] flex flex-col md:flex-row glass border border-white/10 rounded-[4rem] shadow-2xl overflow-hidden">
            <div className="flex-1 flex flex-col overflow-y-auto p-10 md:p-14 bg-black scrollbar-hide">
               <div className="flex justify-between items-start mb-12">
                  <div className="flex items-center gap-6">
                    <div className={`p-5 rounded-[2rem] shadow-2xl bg-gradient-to-br ${selectedItem.gradient}`}>
                       {selectedItem.type === 'curso' ? <PlayCircle size={36} strokeWidth={1.5} /> : <Book size={36} strokeWidth={1.5} />}
                    </div>
                    <div>
                       <h2 className="text-3xl md:text-4xl font-black tracking-tighter mb-2">{selectedItem.title}</h2>
                       <p className="text-gray-500 font-bold text-xs uppercase tracking-widest">{selectedItem.category}</p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedItem(null)} className="p-4 bg-white/5 rounded-full hover:bg-red-500/10 hover:text-red-400 transition-all"><X size={28}/></button>
               </div>

               <div className="aspect-video w-full rounded-[3.5rem] bg-gray-900 overflow-hidden mb-12 border border-white/5 relative group shadow-2xl">
                  <img src={selectedItem.imageUrl} className="w-full h-full object-cover opacity-40" alt={selectedItem.title} />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <a href={selectedItem.videoUrl || '#'} target="_blank" className="p-10 rounded-full bg-white/5 backdrop-blur-3xl border border-white/20 hover:scale-110 transition-all hover:bg-purple-600/20">
                       {selectedItem.type === 'curso' ? <PlayCircle size={80} fill="white" /> : <Book size={80} fill="white" />}
                    </a>
                  </div>
               </div>

               <div className="max-w-4xl space-y-10">
                  <div className="flex items-center justify-between border-b border-white/5 pb-8">
                    <h3 className="text-2xl font-black">{selectedItem.type === 'curso' ? 'Masterclass' : 'Arquivo'}</h3>
                    {selectedItem.videoUrl && (
                      <a href={selectedItem.videoUrl} target="_blank" className="flex items-center gap-3 text-purple-400 font-black text-xs bg-purple-500/10 px-8 py-4 rounded-2xl border border-purple-500/20 hover:bg-purple-600 hover:text-white transition-all">
                        Acessar Agora <ExternalLink size={18}/>
                      </a>
                    )}
                  </div>
                  <p className="text-gray-400 text-xl leading-relaxed italic font-medium">"{selectedItem.description}"</p>
               </div>
            </div>

            <div className="w-full md:w-[480px] bg-[#05070a] border-l border-white/5 flex flex-col">
               <div className="p-12 border-b border-white/5 bg-black/50">
                  <h3 className="text-xl font-black flex items-center gap-3">
                    <MessageSquare size={20} className="text-purple-500" /> 
                    Comentários
                  </h3>
               </div>
               <div className="flex-1 overflow-y-auto p-12 space-y-10 scrollbar-hide">
                  {selectedItem.comments && selectedItem.comments.length > 0 ? selectedItem.comments.map(c => (
                    <div key={c.id} className="space-y-4 animate-fade-in group">
                       <div className="flex justify-between items-center">
                          <span className="text-sm font-black text-purple-400">{c.userName}</span>
                          <span className="text-[9px] text-gray-600 font-black uppercase">{c.timestamp}</span>
                       </div>
                       <div className="p-6 rounded-[2rem] bg-white/[0.03] text-sm text-gray-300 border border-white/5">
                         {c.text}
                       </div>
                    </div>
                  )) : (
                    <div className="h-full flex flex-col items-center justify-center opacity-30">
                       <p className="font-black uppercase tracking-widest text-[9px]">Sem comentários</p>
                    </div>
                  )}
               </div>
               <div className="p-10 border-t border-white/5 bg-black">
                  <form className="relative" onSubmit={(e) => {
                    const input = (e.target as any).comment;
                    handleComment(e, input.value);
                    input.value = '';
                  }}>
                    <input name="comment" type="text" placeholder="Escreva..." className="w-full bg-white/5 border border-white/10 rounded-2xl px-7 py-5 text-sm outline-none focus:ring-1 focus:ring-purple-500 pr-16" />
                    <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-gradient-primary rounded-xl"><Send size={20}/></button>
                  </form>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  if (isLoading && !currentUser) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-black gap-6">
        <Loader2 className="animate-spin text-purple-500" size={64} strokeWidth={1} />
        <p className="font-black tracking-[4px] text-[10px] uppercase text-gray-400">Carregando...</p>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black">
        <div className="glass max-w-md w-full p-12 rounded-[3rem] shadow-2xl border border-white/10 animate-fade-in text-center">
          <h1 className="text-4xl font-black text-gradient-primary tracking-tighter mb-10">VITALÍCIO</h1>
          <form onSubmit={handleAuth} className="space-y-4 text-left">
            {isAuthMode === 'register' && (
              <input type="text" placeholder="Nome" value={authName} onChange={e => setAuthName(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" required />
            )}
            <input type="email" placeholder="E-mail" value={authEmail} onChange={e => setAuthEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" required />
            <input type="password" placeholder="Senha" value={authPassword} onChange={e => setAuthPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" required />
            <button type="submit" className="w-full py-5 rounded-2xl bg-gradient-primary text-white font-black uppercase text-[11px] tracking-widest">
              {isAuthMode === 'login' ? 'Entrar' : 'Registrar'}
            </button>
          </form>
          <button onClick={() => setIsAuthMode(isAuthMode === 'login' ? 'register' : 'login')} className="mt-8 text-[10px] uppercase text-gray-500 font-black">
             Trocar para {isAuthMode === 'login' ? 'Registro' : 'Login'}
          </button>
        </div>
      </div>
    );
  }

  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="space-y-16 animate-fade-in max-w-[1600px] mx-auto">
          <div className="flex justify-between items-end border-b border-white/5 pb-10">
            <h1 className="text-5xl font-black tracking-tighter">Administração</h1>
            <button onClick={fetchData} className="px-8 py-4 bg-white/5 rounded-2xl font-black text-xs border border-white/10 flex items-center gap-2">
              <RotateCcw size={16}/> Atualizar
            </button>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-12 gap-12">
             <div className="xl:col-span-5">
                <div className="glass-card p-10 rounded-[4rem] border border-white/10 shadow-3xl">
                   <h3 className="text-2xl font-black mb-10">{isEditing ? 'Editar' : 'Novo Módulo'}</h3>
                   <form onSubmit={handleAddOrUpdate} className="space-y-8">
                      <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-3xl px-8 py-5 text-sm outline-none" placeholder="Título" />

                      <div className="flex bg-black rounded-3xl p-1.5 border border-white/10">
                         <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'curso'})} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase ${materialForm.type === 'curso' ? 'bg-purple-600' : 'text-gray-500'}`}>Vídeo</button>
                         <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'ebook'})} className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase ${materialForm.type === 'ebook' ? 'bg-blue-600' : 'text-gray-500'}`}>E-book</button>
                      </div>

                      <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-3xl px-8 py-5 text-sm outline-none bg-black">
                         {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>

                      <div className="p-8 rounded-[3rem] bg-white/[0.02] border border-white/5 space-y-4">
                        <div className="flex justify-between">
                           <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px]">Capa</label>
                           <button type="button" onClick={() => fileInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-purple-500/10 text-purple-400 rounded-xl">
                             {isUploading === 'image' ? <Loader2 size={12} className="animate-spin"/> : 'Fazer Upload'}
                           </button>
                        </div>
                        <input type="text" value={materialForm.imageUrl} onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})} className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-xs" placeholder="Link..." />
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'image')} />
                      </div>

                      <div className="p-8 rounded-[3rem] bg-white/[0.02] border border-white/5 space-y-4">
                        <div className="flex justify-between">
                           <label className="text-[10px] font-black uppercase text-gray-500 tracking-[3px]">Conteúdo</label>
                           <button type="button" onClick={() => contentInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-blue-500/10 text-blue-400 rounded-xl">
                             {isUploading === 'content' ? <Loader2 size={12} className="animate-spin"/> : 'Fazer Upload'}
                           </button>
                        </div>
                        <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-xs" placeholder="Link..." />
                        <input type="file" ref={contentInputRef} className="hidden" accept={materialForm.type === 'curso' ? "video/*" : "application/pdf"} onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'content')} />
                      </div>

                      <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-[2.5rem] px-8 py-6 text-sm h-32 resize-none" placeholder="Descrição"></textarea>

                      <button type="submit" disabled={isUploading !== 'none'} className="w-full py-7 bg-gradient-primary rounded-[2.5rem] font-black uppercase text-xs tracking-[5px] disabled:opacity-50">
                        {isEditing ? 'Salvar' : 'Publicar na VPS'}
                      </button>
                   </form>
                </div>
             </div>

             <div className="xl:col-span-7">
                <div className="glass-card rounded-[4rem] border border-white/10 overflow-hidden">
                   <div className="p-12 border-b border-white/10 bg-white/5 flex justify-between">
                      <h3 className="text-xl font-black text-gray-400">Conteúdos Ativos</h3>
                      <span className="px-6 py-2 rounded-full bg-purple-500/10 text-purple-400 font-black text-[10px]">{items.length}</span>
                   </div>
                   <div className="divide-y divide-white/5 max-h-[800px] overflow-y-auto scrollbar-hide">
                      {items.map(item => (
                        <div key={item.id} className="p-10 flex items-center gap-10 hover:bg-white/[0.02]">
                           <img src={item.imageUrl} className="w-20 h-20 rounded-3xl object-cover" alt="" />
                           <div className="flex-1">
                              <h4 className="font-black text-xl truncate tracking-tighter">{item.title}</h4>
                              <p className="text-[10px] text-gray-500 font-black uppercase">{item.category}</p>
                           </div>
                           <div className="flex gap-4">
                              <button onClick={() => { setIsEditing(true); setMaterialForm(item); }} className="p-4 bg-blue-500/5 text-blue-400 rounded-2xl"><Edit3 size={18}/></button>
                              <button onClick={() => handleDelete(item.id)} className="p-4 bg-red-500/5 text-red-400 rounded-2xl"><Trash2 size={18}/></button>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-20 animate-fade-in">
        <section className="relative p-16 md:p-28 rounded-[5rem] overflow-hidden shadow-2xl bg-gradient-to-br from-purple-900 to-pink-600">
           <h1 className="text-6xl md:text-8xl lg:text-9xl font-black mb-10 leading-none tracking-tighter text-white">
              Acesso <br/> <span className="text-black/30">Premium.</span>
           </h1>
           <button onClick={() => setActiveTab('curso')} className="px-16 py-6 rounded-[2rem] bg-white text-black font-black uppercase tracking-[4px] hover:scale-105 transition-all flex items-center gap-4">
              Começar <ArrowRight size={22}/>
           </button>
        </section>

        <div className="flex bg-white/5 p-2.5 rounded-[3rem] border border-white/10 w-fit backdrop-blur-xl">
           {(['todos', 'curso', 'ebook'] as const).map(tab => (
             <button key={tab} onClick={() => setActiveTab(tab)}
               className={`px-10 md:px-16 py-5 rounded-[2.5rem] text-[10px] font-black uppercase tracking-[3px] transition-all ${
                 activeTab === tab ? 'bg-purple-600 text-white' : 'text-gray-500'
               }`}>
               {tab === 'todos' ? 'Ver Tudo' : tab === 'curso' ? 'Vídeos' : 'E-books'}
             </button>
           ))}
        </div>

        <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-10 md:gap-14' : 'space-y-12'}>
          {filteredItemsList.map((item) => (
            <div key={item.id} className="relative group">
               <div className="relative glass-card rounded-[4rem] border border-white/5 overflow-hidden h-full flex flex-col hover:-translate-y-3 transition-all duration-500">
                  <div className="h-72 overflow-hidden relative">
                     <img src={item.imageUrl} className="w-full h-full object-cover" alt={item.title} />
                     <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent"></div>
                  </div>
                  <div className="p-10 flex flex-col flex-1">
                     <h3 className="text-2xl font-black mb-6 tracking-tighter line-clamp-2">{item.title}</h3>
                     <div className="mt-auto flex justify-between items-center border-t border-white/5 pt-8">
                        <span className="text-[10px] font-black text-gray-500 uppercase">{item.category}</span>
                        <button onClick={() => setSelectedItem(item)} className="p-4 bg-purple-600 text-white rounded-3xl"><ArrowRight size={18}/></button>
                     </div>
                  </div>
               </div>
            </div>
          ))}
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, Image as ImageIcon, Info, FileText
} from 'lucide-react';
import { User, Material, CATEGORIES, CATEGORY_ICONS } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  // --- ESTADOS ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);

  // --- UTILITÁRIOS ---
  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    const displayMessage = typeof message === 'string' ? message : (message?.message || "Erro inesperado");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  // --- BUSCA DE DADOS ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData: Material[] = (data || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type as any,
        category: m.category,
        description: m.description,
        imageUrl: m.image_url,
        videoUrl: m.video_url,
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      console.error("Erro Fetch:", e);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- UPLOAD ---
  const handleFileUpload = async (file: File, type: 'image' | 'content') => {
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('materials').getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa carregada!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Conteúdo pronto!");
      }
    } catch (e: any) {
      addToast(e.message || "Erro no upload. Verifique o bucket 'materials'.", 'error');
    } finally {
      setIsUploading('none');
    }
  };

  // --- AUTENTICAÇÃO ---
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin', name: 'Administrador', email: authEmail, isAdmin: true });
      addToast("Modo Admin Ativo");
    } else {
      setCurrentUser({ id: 'user-' + Date.now(), name: authName || 'Membro', email: authEmail, isAdmin: false });
      addToast("Bem-vindo!");
    }
  };

  // --- CRUD ---
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return addToast("Preencha os campos obrigatórios", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      let error;
      if (isEditing && materialForm.id) {
        const res = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        error = res.error;
      } else {
        const res = await supabase.from('materials').insert([payload]);
        error = res.error;
      }
      if (error) throw error;

      addToast("Salvo com sucesso!");
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao salvar dados.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Excluir permanentemente?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Removido.");
      fetchData();
    } catch (e: any) {
      addToast("Erro ao excluir.", 'error');
    }
  };

  const handleComment = async (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;
    try {
      const { error } = await supabase.from('comments').insert([{
        material_id: selectedItem.id,
        user_name: currentUser.name,
        text: text,
        timestamp: new Date().toLocaleDateString('pt-BR')
      }]);
      if (error) throw error;
      fetchData();
      addToast("Comentário enviado");
    } catch (e: any) {
      addToast("Erro ao comentar", 'error');
    }
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  // --- COMPONENTES DE LAYOUT ---
  const DashboardLayout = ({ children }: { children: React.ReactNode }) => (
    <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
      <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
        {toasts.map(t => (
          <div key={t.id} className={`animate-slide-in glass px-6 py-4 rounded-2xl border-l-4 pointer-events-auto flex items-center gap-3 ${t.type === 'error' ? 'border-red-500' : 'border-purple-500'}`}>
            {t.type === 'error' ? <AlertCircle size={18} className="text-red-400" /> : <CheckCircle size={18} className="text-purple-400" />}
            <span className="text-xs font-bold">{t.message}</span>
          </div>
        ))}
      </div>

      <aside className="w-full md:w-64 lg:w-72 glass border-r border-white/10 p-6 flex flex-col gap-8 bg-[#050505]/90">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2.5 rounded-xl bg-gradient-primary shadow-xl"><Layers size={22} /></div>
          <h2 className="text-2xl font-black text-gradient-primary">VITALÍCIO</h2>
        </div>

        <div className="p-5 rounded-3xl glass-card border border-white/10 flex items-center gap-4">
          <div className="w-10 h-10 rounded-xl bg-gradient-primary flex items-center justify-center font-bold">{currentUser?.name[0]}</div>
          <div className="min-w-0">
            <p className="text-sm font-bold truncate">{currentUser?.name}</p>
            <p className="text-[9px] uppercase opacity-50">{currentUser?.isAdmin ? 'Admin' : 'Membro'}</p>
          </div>
        </div>

        <nav className="space-y-1">
          <p className="text-[10px] font-black text-gray-600 uppercase tracking-widest mb-4 ml-4">Categorias</p>
          {['Todos', ...CATEGORIES].map(cat => {
            const Icon = CATEGORY_ICONS[cat] || LayoutDashboard;
            return (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`w-full text-left px-5 py-4 rounded-2xl text-xs font-bold transition-all flex items-center gap-4 ${activeCategory === cat ? 'bg-purple-600 shadow-lg' : 'text-gray-500 hover:bg-white/5'}`}>
                <Icon size={18} /> {cat}
              </button>
            );
          })}
        </nav>

        <div className="mt-auto">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center justify-center gap-3 px-6 py-4 rounded-2xl bg-white/5 text-gray-500 font-bold hover:text-red-400">
            <LogOut size={18} /> Sair
          </button>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto scrollbar-hide">
        <header className="sticky top-0 z-40 px-6 py-6 glass border-b border-white/5 flex items-center justify-between bg-black/60 backdrop-blur-xl">
          <div className="flex-1 max-w-xl relative">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
            <input type="text" placeholder="Buscar..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl pl-16 pr-8 py-4 text-sm outline-none focus:ring-1 focus:ring-purple-500" />
          </div>
          <div className="flex items-center gap-4 ml-6">
            <button onClick={fetchData} className="p-4 bg-white/5 rounded-xl hover:bg-white/10"><RotateCcw size={18} /></button>
            <div className="flex bg-white/5 p-1 rounded-xl">
              <button onClick={() => setViewMode('grid')} className={`p-2 rounded-lg ${viewMode === 'grid' ? 'bg-purple-600' : 'text-gray-500'}`}><Grid size={18} /></button>
              <button onClick={() => setViewMode('list')} className={`p-2 rounded-lg ${viewMode === 'list' ? 'bg-purple-600' : 'text-gray-500'}`}><List size={18} /></button>
            </div>
          </div>
        </header>
        <div className="p-6 md:p-12 pb-32">{children}</div>
      </main>

      {/* MODAL DE DETALHES */}
      {selectedItem && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 animate-fade-in">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-xl" onClick={() => setSelectedItem(null)}></div>
          <div className="relative w-full max-w-6xl h-full max-h-[90vh] flex flex-col md:flex-row glass border border-white/10 rounded-[3rem] overflow-hidden">
            <div className="flex-1 overflow-y-auto p-10 bg-black scrollbar-hide">
              <div className="flex justify-between items-start mb-10">
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl bg-gradient-to-br ${selectedItem.gradient}`}>
                    {selectedItem.type === 'curso' ? <PlayCircle size={32} /> : <Book size={32} />}
                  </div>
                  <div>
                    <h2 className="text-3xl font-black">{selectedItem.title}</h2>
                    <p className="text-xs text-gray-500 uppercase tracking-widest">{selectedItem.category}</p>
                  </div>
                </div>
                <button onClick={() => setSelectedItem(null)} className="p-3 bg-white/5 rounded-full hover:bg-red-500/20"><X size={24} /></button>
              </div>

              <div className="aspect-video w-full rounded-[2rem] bg-gray-900 overflow-hidden mb-10 border border-white/5 relative group">
                <img src={selectedItem.imageUrl} className="w-full h-full object-cover opacity-50" alt="" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <a href={selectedItem.videoUrl} target="_blank" className="p-8 rounded-full bg-purple-600 hover:scale-110 transition-all shadow-2xl">
                    {selectedItem.type === 'curso' ? <PlayCircle size={50} fill="white" /> : <Book size={50} fill="white" />}
                  </a>
                </div>
              </div>
              <p className="text-gray-400 text-lg italic leading-relaxed">"{selectedItem.description}"</p>
            </div>

            <div className="w-full md:w-96 bg-[#080808] border-l border-white/5 flex flex-col">
              <div className="p-8 border-b border-white/5"><h3 className="font-black flex items-center gap-2"><MessageSquare size={18} /> Debate</h3></div>
              <div className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide">
                {selectedItem.comments?.map(c => (
                  <div key={c.id} className="space-y-2">
                    <div className="flex justify-between text-[10px] font-black uppercase"><span className="text-purple-400">{c.userName}</span><span className="text-gray-600">{c.timestamp}</span></div>
                    <div className="p-4 rounded-2xl bg-white/5 text-xs text-gray-300 border border-white/5">{c.text}</div>
                  </div>
                ))}
              </div>
              <div className="p-6 border-t border-white/5 bg-black">
                <form className="relative" onSubmit={(e) => {
                  const input = (e.target as any).comment;
                  handleComment(e, input.value);
                  input.value = '';
                }}>
                  <input name="comment" type="text" placeholder="Escreva..." className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-xs outline-none" />
                  <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 p-2 bg-purple-600 rounded-lg"><Send size={16} /></button>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // --- RENDERS CONDICIONAIS ---
  if (isLoading && !currentUser) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-black gap-4">
        <Loader2 className="animate-spin text-purple-500" size={48} />
        <p className="text-[10px] uppercase font-black tracking-widest text-gray-500">Acessando VPS...</p>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-6">
        <div className="glass max-w-sm w-full p-10 rounded-[2.5rem] shadow-2xl border border-white/10 text-center animate-fade-in">
          <h1 className="text-3xl font-black text-gradient-primary mb-8">VITALÍCIO</h1>
          <form onSubmit={handleAuth} className="space-y-4 text-left">
            {isAuthMode === 'register' && <input type="text" placeholder="Nome" value={authName} onChange={e => setAuthName(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-white outline-none" required />}
            <input type="email" placeholder="E-mail" value={authEmail} onChange={e => setAuthEmail(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-white outline-none" required />
            <input type="password" placeholder="Senha" value={authPassword} onChange={e => setAuthPassword(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-white outline-none" required />
            <button type="submit" className="w-full py-4 rounded-xl bg-gradient-primary font-black uppercase text-[10px] tracking-widest">Entrar</button>
          </form>
          <button onClick={() => setIsAuthMode(isAuthMode === 'login' ? 'register' : 'login')} className="mt-6 text-[10px] font-black text-gray-500 uppercase">Trocar para {isAuthMode === 'login' ? 'Registro' : 'Login'}</button>
        </div>
      </div>
    );
  }

  if (currentUser.isAdmin) {
    return (
      <DashboardLayout>
        <div className="max-w-6xl mx-auto space-y-12 animate-fade-in">
          <div className="flex justify-between items-end border-b border-white/10 pb-8">
            <h1 className="text-4xl font-black">Painel de Controle</h1>
            <div className="flex gap-4">
               <button onClick={fetchData} className="px-6 py-3 bg-white/5 rounded-xl text-xs font-bold border border-white/10 flex items-center gap-2"><RotateCcw size={14}/> Sincronizar</button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
            <div className="lg:col-span-5">
              <div className="glass-card p-8 rounded-[2rem] border border-white/10">
                <h3 className="text-xl font-black mb-8">{isEditing ? 'Editar Módulo' : 'Novo Conteúdo'}</h3>
                <form onSubmit={handleSave} className="space-y-6">
                  <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 text-sm" placeholder="Título" />
                  <div className="flex bg-black rounded-xl p-1 border border-white/10">
                    <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'curso'})} className={`flex-1 py-3 rounded-lg text-[10px] font-bold uppercase ${materialForm.type === 'curso' ? 'bg-purple-600' : 'text-gray-500'}`}>Vídeo</button>
                    <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'ebook'})} className={`flex-1 py-3 rounded-lg text-[10px] font-bold uppercase ${materialForm.type === 'ebook' ? 'bg-blue-600' : 'text-gray-500'}`}>PDF</button>
                  </div>
                  <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 text-sm bg-black">
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>

                  <div className="p-6 rounded-2xl bg-white/5 border border-white/5 space-y-4">
                    <div className="flex justify-between items-center"><label className="text-[10px] font-bold text-gray-500 uppercase">Capa</label><button type="button" onClick={() => fileInputRef.current?.click()} className="text-[9px] px-3 py-1.5 bg-purple-600 rounded-lg">{isUploading === 'image' ? '...' : 'Upload'}</button></div>
                    <input type="text" value={materialForm.imageUrl} onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-xs" placeholder="Link da imagem..." />
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'image')} />
                  </div>

                  <div className="p-6 rounded-2xl bg-white/5 border border-white/5 space-y-4">
                    <div className="flex justify-between items-center"><label className="text-[10px] font-bold text-gray-500 uppercase">Conteúdo</label><button type="button" onClick={() => contentInputRef.current?.click()} className="text-[9px] px-3 py-1.5 bg-blue-600 rounded-lg">{isUploading === 'content' ? '...' : 'Upload'}</button></div>
                    <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-xs" placeholder="Link do arquivo..." />
                    <input type="file" ref={contentInputRef} className="hidden" accept={materialForm.type === 'curso' ? "video/*" : "application/pdf"} onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'content')} />
                  </div>

                  <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-6 py-4 text-sm h-28 resize-none" placeholder="Breve descrição"></textarea>
                  <button type="submit" disabled={isUploading !== 'none'} className="w-full py-5 rounded-xl bg-gradient-primary font-black uppercase text-xs tracking-widest disabled:opacity-50">Publicar Conteúdo</button>
                </form>
              </div>
            </div>

            <div className="lg:col-span-7">
              <div className="glass-card rounded-[2rem] border border-white/10 overflow-hidden">
                <div className="p-8 border-b border-white/5 bg-white/5 flex justify-between items-center"><h3 className="font-bold text-gray-400 uppercase text-xs">Biblioteca Ativa</h3><span className="px-3 py-1 bg-purple-500/20 text-purple-400 rounded-lg text-[10px]">{items.length}</span></div>
                <div className="divide-y divide-white/5 max-h-[700px] overflow-y-auto scrollbar-hide">
                  {items.map(item => (
                    <div key={item.id} className="p-8 flex items-center gap-6 hover:bg-white/5">
                      <img src={item.imageUrl} className="w-16 h-16 rounded-xl object-cover" alt="" />
                      <div className="flex-1 min-w-0">
                        <h4 className="font-bold truncate">{item.title}</h4>
                        <p className="text-[10px] text-gray-500 uppercase">{item.category}</p>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => { setIsEditing(true); setMaterialForm(item); }} className="p-3 bg-blue-500/10 text-blue-400 rounded-xl"><Edit3 size={16}/></button>
                        <button onClick={() => handleDelete(item.id)} className="p-3 bg-red-500/10 text-red-400 rounded-xl"><Trash2 size={16}/></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-16 animate-fade-in">
        <section className="relative p-12 md:p-24 rounded-[3rem] overflow-hidden bg-gradient-to-br from-purple-900 via-purple-700 to-pink-600">
          <div className="relative z-10">
            <h1 className="text-5xl md:text-8xl font-black mb-8 leading-none tracking-tighter">Sua Jornada <br/> Vitalícia.</h1>
            <button onClick={() => setActiveTab('curso')} className="px-10 py-5 bg-white text-black font-black uppercase text-xs rounded-2xl flex items-center gap-3 hover:scale-105 transition-all">Começar Agora <ArrowRight size={20}/></button>
          </div>
        </section>

        <div className="flex bg-white/5 p-2 rounded-2xl border border-white/10 w-fit backdrop-blur-xl">
          {(['todos', 'curso', 'ebook'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-10 py-4 rounded-xl text-[10px] font-bold uppercase transition-all ${activeTab === tab ? 'bg-purple-600' : 'text-gray-500'}`}>
              {tab === 'todos' ? 'Ver Tudo' : tab === 'curso' ? 'Vídeos' : 'PDFs'}
            </button>
          ))}
        </div>

        <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-8' : 'space-y-8'}>
          {filteredItems.map(item => (
            <div key={item.id} className="glass-card rounded-[2.5rem] border border-white/5 overflow-hidden flex flex-col hover:-translate-y-2 transition-all duration-500 group">
              <div className="h-64 overflow-hidden relative">
                <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt="" />
                <div className="absolute top-6 left-6"><span className="px-4 py-2 glass rounded-xl text-[9px] font-black uppercase tracking-widest">{item.type}</span></div>
              </div>
              <div className="p-8 flex flex-col flex-1">
                <h3 className="text-xl font-bold mb-4 line-clamp-2">{item.title}</h3>
                <div className="mt-auto flex justify-between items-center pt-6 border-t border-white/5">
                  <span className="text-[9px] font-black text-gray-500 uppercase">{item.category}</span>
                  <button onClick={() => setSelectedItem(item)} className="p-3 bg-purple-600 rounded-2xl"><ArrowRight size={18}/></button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, Image as ImageIcon, Info, FileText
} from 'lucide-react';
import { User, Material, CATEGORIES, CATEGORY_ICONS, MaterialType } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const App: React.FC = () => {
  // --- ESTADOS ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);

  // --- UTILITÁRIOS ---
  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    const displayMessage = typeof message === 'string' ? message : (message?.message || "Erro inesperado");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  // --- BUSCA DE DADOS ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      const formattedData: Material[] = (data || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type as MaterialType,
        category: m.category,
        description: m.description || '',
        imageUrl: m.image_url || '',
        videoUrl: m.video_url || '',
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      console.error("Erro Fetch:", e);
      addToast("Erro ao conectar à VPS. Verifique as tabelas.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- UPLOAD ---
  const handleFileUpload = async (file: File, type: 'image' | 'content') => {
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('materials').getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa carregada com sucesso!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Arquivo salvo na VPS!");
      }
    } catch (e: any) {
      addToast(e.message || "Erro no upload. Certifique-se de que o Bucket 'materials' existe.", 'error');
    } finally {
      setIsUploading('none');
    }
  };

  // --- AUTENTICAÇÃO ---
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin', name: 'Diretoria Vitalício', email: authEmail, isAdmin: true });
      addToast("Acesso Administrativo Liberado");
    } else {
      setCurrentUser({ id: 'user-' + Date.now(), name: authName || 'Membro Elite', email: authEmail, isAdmin: false });
      addToast("Bem-vindo à Academia!");
    }
  };

  // --- SALVAR/CRUD ---
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) {
      return addToast("Título e Capa são obrigatórios.", 'error');
    }

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      let error;
      if (isEditing && materialForm.id) {
        const res = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        error = res.error;
      } else {
        const res = await supabase.from('materials').insert([payload]);
        error = res.error;
      }

      if (error) throw error;

      addToast("Conteúdo publicado com sucesso!");
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao salvar no banco da VPS.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Deseja deletar este conteúdo permanentemente?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Conteúdo removido.");
      fetchData();
    } catch (e: any) {
      addToast("Erro ao deletar.", 'error');
    }
  };

  const handleComment = async (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;
    try {
      const { error } = await supabase.from('comments').insert([{
        material_id: selectedItem.id,
        user_name: currentUser.name,
        text: text,
        timestamp: new Date().toLocaleDateString('pt-BR')
      }]);
      if (error) throw error;
      fetchData();
      addToast("Comentário enviado");
    } catch (e: any) {
      addToast("Erro ao comentar", 'error');
    }
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  // --- COMPONENTE DE LAYOUT (Unificado) ---
  const DashboardLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    return (
      <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
        {/* TOASTS AREA */}
        <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
          {toasts.map(t => (
            <div key={t.id} className={`animate-slide-in glass px-6 py-4 rounded-2xl border-l-4 pointer-events-auto flex items-center gap-3 shadow-2xl ${t.type === 'error' ? 'border-red-500 bg-red-500/5' : 'border-purple-500'}`}>
