            <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }} className="w-full flex items-center justify-center gap-3 px-6 py-4 rounded-2xl bg-white/5 text-gray-500 font-bold hover:bg-red-500/10 hover:text-red-400 transition-all border border-transparent hover:border-red-500/20">
