                <h3 className="text-2xl font-black mb-10 flex items-center gap-4">
                   {isEditing ? <Edit3 size={24} className="text-blue-400" /> : <Plus size={24} className="text-purple-400" />}
                   {isEditing ? 'Editar Registro' : 'Lançar Novo Conteúdo'}
                </h3>
                <form onSubmit={handleSave} className="space-y-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-gray-600 tracking-widest ml-4">Nome do Módulo</label>
                    <input type="text" value={materialForm.title} onChange={e => setMaterialForm({...materialForm, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-7 py-5 text-sm outline-none focus:ring-1 focus:ring-purple-500 transition-all" placeholder="Ex: IP do Milhão" />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-gray-600 tracking-widest ml-4">Tipo de Material</label>
                    <div className="flex bg-black rounded-2xl p-1.5 border border-white/10">
                      <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'curso'})} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${materialForm.type === 'curso' ? 'bg-purple-600 text-white shadow-xl' : 'text-gray-500'}`}>Videoaula</button>
                      <button type="button" onClick={() => setMaterialForm({...materialForm, type: 'ebook'})} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${materialForm.type === 'ebook' ? 'bg-blue-600 text-white shadow-xl' : 'text-gray-500'}`}>E-book / PDF</button>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-gray-600 tracking-widest ml-4">Categoria</label>
                    <select value={materialForm.category} onChange={e => setMaterialForm({...materialForm, category: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-7 py-5 text-sm outline-none bg-black font-bold">
                      {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>

                  {/* UPLOADS */}
                  <div className="p-8 rounded-[2.5rem] bg-white/[0.02] border border-white/5 space-y-6">
                    <div className="flex justify-between items-center">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2"><ImageIcon size={14}/> Capa (Imagem)</label>
                       <button type="button" onClick={() => fileInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-purple-600 rounded-xl hover:bg-purple-500 transition-all shadow-lg flex items-center gap-2">
                         {isUploading === 'image' ? <Loader2 size={12} className="animate-spin" /> : <><UploadCloud size={12}/> Subir Capa</>}
                       </button>
                    </div>
                    <input type="text" value={materialForm.imageUrl} onChange={e => setMaterialForm({...materialForm, imageUrl: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-xl px-5 py-4 text-[10px] text-gray-500" placeholder="URL da Capa..." />
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'image')} />
                  </div>

                  <div className="p-8 rounded-[2.5rem] bg-white/[0.02] border border-white/5 space-y-6">
                    <div className="flex justify-between items-center">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2"><FileText size={14}/> Arquivo / Conteúdo</label>
                       <button type="button" onClick={() => contentInputRef.current?.click()} className="text-[9px] font-black uppercase px-4 py-2 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all shadow-lg flex items-center gap-2">
                         {isUploading === 'content' ? <Loader2 size={12} className="animate-spin" /> : <><UploadCloud size={12}/> Subir Arquivo</>}
                       </button>
                    </div>
                    <input type="text" value={materialForm.videoUrl} onChange={e => setMaterialForm({...materialForm, videoUrl: e.target.value})} className="w-full bg-black/50 border border-white/10 rounded-xl px-5 py-4 text-[10px] text-gray-500" placeholder="URL do Conteúdo..." />
                    <input type="file" ref={contentInputRef} className="hidden" accept={materialForm.type === 'curso' ? "video/*" : "application/pdf"} onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0], 'content')} />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-gray-600 tracking-widest ml-4">Breve Descrição</label>
                    <textarea value={materialForm.description} onChange={e => setMaterialForm({...materialForm, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-3xl px-7 py-5 text-sm h-32 resize-none outline-none focus:ring-1 focus:ring-purple-500" placeholder="O que o aluno vai aprender?"></textarea>
                  </div>

                  <button type="submit" disabled={isUploading !== 'none'} className="w-full py-7 rounded-[2rem] bg-gradient-primary font-black uppercase text-[11px] tracking-[6px] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50">
                    {isEditing ? 'Salvar Alterações' : 'Publicar na Biblioteca'}
                  </button>
                  {isEditing && (
                    <button type="button" onClick={() => { setIsEditing(false); setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' }); }} className="w-full py-4 text-[9px] font-black uppercase text-gray-600 hover:text-white transition-colors">Cancelar Edição</button>
                  )}
                </form>
              </div>
            </div>

            {/* LISTA DE CONTEÚDOS */}
            <div className="lg:col-span-7">
              <div className="glass-card rounded-[3rem] border border-white/10 overflow-hidden shadow-2xl">
                <div className="p-10 border-b border-white/5 bg-white/5 flex justify-between items-center">
                  <h3 className="font-black text-gray-400 uppercase tracking-widest text-xs">Módulos Hospedados</h3>
                  <span className="px-5 py-2 bg-purple-500/10 text-purple-400 rounded-xl font-black text-[11px] border border-purple-500/20">{items.length} Ativos</span>
                </div>
                <div className="divide-y divide-white/5 max-h-[1200px] overflow-y-auto scrollbar-hide">
                  {items.map(item => (
                    <div key={item.id} className="p-10 flex items-center gap-8 hover:bg-white/[0.03] transition-colors group">
                      <div className="relative w-20 h-20 shrink-0">
                         <img src={item.imageUrl} className="w-full h-full rounded-2xl object-cover shadow-xl border border-white/10" alt="" />
                         <div className="absolute -top-2 -right-2 p-1.5 rounded-lg bg-black/80 border border-white/10">
                            {item.type === 'curso' ? <PlayCircle size={14} className="text-purple-400" /> : <Book size={14} className="text-blue-400" />}
                         </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="font-black text-xl truncate tracking-tight group-hover:text-purple-400 transition-colors mb-1">{item.title}</h4>
                        <div className="flex items-center gap-4 text-[10px] font-black text-gray-600 uppercase tracking-widest">
                           <span>{item.category}</span>
                           <span>•</span>
                           <span className="flex items-center gap-1"><Eye size={12}/> {item.views}</span>
                        </div>
                      </div>
                      <div className="flex gap-3">
                        <button onClick={() => { setIsEditing(true); setMaterialForm(item); window.scrollTo({top: 0, behavior: 'smooth'}); }} className="p-4 bg-blue-500/5 text-blue-400 rounded-2xl hover:bg-blue-500/10 transition-all border border-blue-500/10 shadow-lg"><Edit3 size={18}/></button>
                        <button onClick={() => handleDelete(item.id)} className="p-4 bg-red-500/5 text-red-400 rounded-2xl hover:bg-red-500/10 transition-all border border-red-500/10 shadow-lg"><Trash2 size={18}/></button>
                      </div>
                    </div>
                  ))}
                  {items.length === 0 && (
                    <div className="p-40 text-center opacity-20 flex flex-col items-center">
                       <Database size={48} className="mb-4" />
                       <p className="font-black uppercase tracking-[8px]">Nenhum Dado</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </DashboardLayout>
    );
  }

  // --- RENDER DO USUÁRIO (ALUNO) ---
  return (
    <DashboardLayout>
      <div className="space-y-20 animate-fade-in max-w-[1600px] mx-auto">
        {/* HERO BANNER */}
        <section className="relative p-16 md:p-32 rounded-[4rem] overflow-hidden shadow-3xl bg-gradient-to-br from-purple-900 via-purple-700 to-pink-600 group">
          <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>
          <div className="relative z-10 max-w-4xl">
            <div className="inline-flex items-center gap-3 px-8 py-3 rounded-full glass border border-white/20 text-[11px] font-black uppercase tracking-[5px] mb-12 shadow-2xl">
              <Star size={18} fill="currentColor" className="text-yellow-400" /> Membro Vitalício Premium
            </div>
            <h1 className="text-6xl md:text-9xl font-black mb-10 leading-none tracking-tighter text-white">
              Domine <br/> <span className="text-black/30">O Próximo Nível.</span>
            </h1>
            <p className="text-xl md:text-2xl text-white/80 font-medium mb-16 leading-relaxed italic max-w-2xl">
              Sua biblioteca privada de alta performance, agora 100% online e sob seu comando.
            </p>
            <button onClick={() => { setActiveTab('curso'); window.scrollTo({top: 800, behavior: 'smooth'}); }} className="px-16 py-6 rounded-[2rem] bg-white text-black font-black uppercase text-xs tracking-[5px] hover:shadow-[0_20px_60px_rgba(255,255,255,0.2)] hover:scale-105 transition-all flex items-center gap-4 active:scale-95 shadow-2xl">
              Explorar Conteúdo <ArrowRight size={22}/>
            </button>
          </div>
        </section>

        {/* FILTROS DE MÍDIA */}
        <div className="flex bg-white/5 p-2.5 rounded-[2.5rem] border border-white/10 w-fit backdrop-blur-xl shadow-2xl mx-auto md:mx-0">
          {(['todos', 'curso', 'ebook'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-12 md:px-20 py-5 rounded-[2rem] text-[10px] md:text-[11px] font-black uppercase tracking-[4px] transition-all duration-500 ${activeTab === tab ? 'bg-purple-600 text-white shadow-[0_10px_40px_rgba(147,51,234,0.4)] scale-[1.05]' : 'text-gray-500 hover:text-white'}`}>
              {tab === 'todos' ? 'Ver Tudo' : tab === 'curso' ? 'Vídeos' : 'E-books'}
            </button>
          ))}
        </div>

        {/* GRID DE CONTEÚDOS */}
        <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-12 md:gap-16' : 'space-y-10'}>
          {filteredItems.map((item, index) => (
            <div key={item.id} className="relative group animate-fade-in" style={{ animationDelay: `${index * 50}ms` }}>
              <div className={`absolute -inset-2 bg-gradient-to-r ${item.gradient} rounded-[3.5rem] opacity-0 group-hover:opacity-20 blur-2xl transition-all duration-700`}></div>
              <div className="relative glass-card rounded-[3.5rem] border border-white/5 overflow-hidden h-full flex flex-col hover:-translate-y-3 transition-all duration-500 shadow-2xl hover:border-purple-500/30">
                <div className="h-72 overflow-hidden relative">
                  <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1.5s]" alt={item.title} />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>
                  <div className="absolute top-6 left-6">
                     <span className="px-5 py-2 glass rounded-2xl text-[10px] font-black uppercase tracking-[3px] shadow-2xl border border-white/10 backdrop-blur-2xl">
                        {item.type === 'curso' ? 'Vídeo' : 'E-book'}
                     </span>
                  </div>
                </div>
                <div className="p-10 flex flex-col flex-1">
                  <h3 className="text-2xl font-black mb-5 tracking-tighter line-clamp-2 group-hover:text-purple-400 transition-colors">{item.title}</h3>
                  <p className="text-gray-500 text-sm leading-relaxed line-clamp-2 mb-8 italic font-medium opacity-80">"{item.description || 'Sem descrição.'}"</p>

                  <div className="mt-auto flex justify-between items-center pt-8 border-t border-white/5">
                    <div className="flex flex-col">
                       <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">{item.category}</span>
                       <span className="text-[9px] font-black text-purple-600 uppercase flex items-center gap-1"><Eye size={12}/> {item.views.toLocaleString()} acessos</span>
                    </div>
                    <button onClick={() => setSelectedItem(item)} className="p-4 bg-purple-600/10 text-purple-400 rounded-2xl hover:bg-purple-600 hover:text-white transition-all shadow-xl border border-purple-500/20 active:scale-95">
                      <ArrowRight size={20}/>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
          {filteredItems.length === 0 && (
            <div className="col-span-full py-40 text-center opacity-10">
               <Search size={80} className="mx-auto mb-6" />
               <p className="text-4xl font-black uppercase tracking-[15px]">Vazio</p>
            </div>
          )}
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

export type MaterialType = 'curso' | 'ebook';

export interface Comment {
  id: string;
  userName: string;
  text: string;
  timestamp: string;
}

export interface Material {
  id: string;
  title: string;
  type: MaterialType;
  category: string;
  description: string;
  imageUrl: string;
  videoUrl?: string; // For course simulation
  views: number;
  comments: Comment[];
  isReadBy: string[];
  gradient: string;
}

export interface AppSettings {
  heroTitle: string;
  heroSubtitle: string;
  heroImageUrl: string;
  heroButtonText: string;
  heroButtonLink: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  isAdmin: boolean;
}

export const CATEGORIES = [
  'Desenvolvimento Pessoal',
  'Finanças',
  'Produtividade',
  'Bem-estar',
  'Marketing',
  'Filosofia',
  'Tecnologia'
];

import { 
  User as UserIcon, 
  DollarSign, 
  Zap, 
  Heart, 
  TrendingUp, 
  BookOpen, 
  Code,
  Layout
} from 'lucide-react';

export const CATEGORY_ICONS: Record<string, any> = {
  'Todos': Layout,
  'Desenvolvimento Pessoal': UserIcon,
  'Finanças': DollarSign,
  'Produtividade': Zap,
  'Bem-estar': Heart,
  'Marketing': TrendingUp,
  'Filosofia': BookOpen,
  'Tecnologia': Code
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, Image as ImageIcon, Info, FileText, UploadCloud,
  Settings as SettingsIcon, Monitor
} from 'lucide-react';
import { User, Material, AppSettings, CATEGORIES, CATEGORY_ICONS, MaterialType } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const DEFAULT_SETTINGS: AppSettings = {
  heroTitle: "Domine\nO Próximo Nível.",
  heroSubtitle: "Sua biblioteca privada de alta performance, agora 100% online e sob seu comando.",
  heroImageUrl: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1964&auto=format&fit=crop",
  heroButtonText: "Explorar Conteúdo",
  heroButtonLink: "#vitrine"
};

const App: React.FC = () => {
  // --- ESTADOS ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content' | 'hero'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [adminTab, setAdminTab] = useState<'conteudo' | 'vitrine'>('conteudo');
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);

  // --- UTILITÁRIOS ---
  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    const displayMessage = typeof message === 'string' ? message : (message?.message || "Erro inesperado");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  // --- BUSCA DE DADOS ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      // Fetch Materials
      const { data: mData, error: mError } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (mError) throw mError;

      // Fetch Settings
      const { data: sData, error: sError } = await supabase
        .from('settings')
        .select('*')
        .single();

      if (!sError && sData) {
        setSettings({
          heroTitle: sData.hero_title || DEFAULT_SETTINGS.heroTitle,
          heroSubtitle: sData.hero_subtitle || DEFAULT_SETTINGS.heroSubtitle,
          heroImageUrl: sData.hero_image_url || DEFAULT_SETTINGS.heroImageUrl,
          heroButtonText: sData.hero_button_text || DEFAULT_SETTINGS.heroButtonText,
          heroButtonLink: sData.hero_button_link || DEFAULT_SETTINGS.heroButtonLink,
        });
      }

      const formattedData: Material[] = (mData || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type as MaterialType,
        category: m.category,
        description: m.description || '',
        imageUrl: m.image_url || '',
        videoUrl: m.video_url || '',
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      console.error("Erro Fetch:", e);
      addToast("Erro ao conectar à VPS. Verifique se as tabelas existem.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- UPLOAD ---
  const handleFileUpload = async (file: File, type: 'image' | 'content' | 'hero') => {
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('materials').getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa carregada!");
      } else if (type === 'hero') {
        setSettings(prev => ({ ...prev, heroImageUrl: data.publicUrl }));
        addToast("Banner da Vitrine pronto!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Conteúdo salvo na VPS!");
      }
    } catch (e: any) {
      addToast(e.message || "Erro no upload. Verifique o bucket 'materials'.", 'error');
    } finally {
      setIsUploading('none');
    }
  };

  // --- CONFIGURAÇÕES ---
  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const payload = {
        hero_title: settings.heroTitle,
        hero_subtitle: settings.heroSubtitle,
        hero_image_url: settings.heroImageUrl,
        hero_button_text: settings.heroButtonText,
        hero_button_link: settings.heroButtonLink,
      };

      // Tenta atualizar o único registro de settings (id 1 ou o que existir)
      const { data: existing } = await supabase.from('settings').select('id').limit(1);

      let error;
      if (existing && existing.length > 0) {
        const res = await supabase.from('settings').update(payload).eq('id', existing[0].id);
        error = res.error;
      } else {
        const res = await supabase.from('settings').insert([payload]);
        error = res.error;
      }

      if (error) throw error;
      addToast("Vitrine atualizada!");
    } catch (e: any) {
      addToast("Crie a tabela 'settings' no SQL Editor para salvar.", "error");
    }
  };

  // --- AUTENTICAÇÃO ---
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authEmail === 'admin@academia.com' && authPassword === 'admin123') {
      setCurrentUser({ id: 'admin', name: 'Diretoria Vitalício', email: authEmail, isAdmin: true });
      addToast("Acesso Administrativo");
    } else {
      setCurrentUser({ id: 'user-' + Date.now(), name: authName || 'Membro Elite', email: authEmail, isAdmin: false });
      addToast("Bem-vindo!");
    }
  };

  // --- CRUD MATERIAIS ---
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return addToast("Preencha os campos obrigatórios", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      let error;
      if (isEditing && materialForm.id) {
        const res = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        error = res.error;
      } else {
        const res = await supabase.from('materials').insert([payload]);
        error = res.error;
      }
      if (error) throw error;

      addToast("Publicado com sucesso!");
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
