             <div className="text-[9px] font-black uppercase text-gray-700 flex items-center gap-3 px-4 py-2 bg-white/5 rounded-xl">
               <div className={`w-2 h-2 rounded-full ${dbStatus === 'connected' ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
               VPS: {dbStatus === 'connected' ? 'Operacional' : 'Offline'}
            </div>
            <button onClick={() => { setCurrentUser(null); setSelectedItem(null); }} className="w-full flex items-center justify-center gap-4 px-8 py-5 rounded-3xl bg-red-500/5 text-red-400 font-black text-xs hover:bg-red-500/10 transition-all border border-red-500/10">
              <LogOut size={18} /> Encerrar Sessão
