                         <span className="text-[10px] font-black text-purple-600 uppercase flex items-center gap-2"><Eye size={14}/> {item.views.toLocaleString()} acessos</span>
                      </div>
                      <button onClick={() => setSelectedItem(item)} className="p-6 bg-purple-600/10 text-purple-400 rounded-3xl hover:bg-purple-600 hover:text-white transition-all shadow-2xl border border-purple-500/20 active:scale-90 group-hover:scale-110">
                        <ArrowRight size={28}/>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-60 text-center opacity-10 flex flex-col items-center">
                 <Search size={120} className="mb-10" strokeWidth={1} />
                 <p className="text-5xl font-black uppercase tracking-[25px]">Vazio</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, Image as ImageIcon, Info, FileText, UploadCloud,
  Settings as SettingsIcon, Monitor, Sparkles
} from 'lucide-react';
import { User, Material, AppSettings, CATEGORIES, CATEGORY_ICONS, MaterialType } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-purple-600 to-pink-500',
    'from-blue-600 to-cyan-500',
    'from-orange-500 to-red-500',
    'from-green-500 to-emerald-600',
    'from-indigo-600 to-purple-600'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const DEFAULT_SETTINGS: AppSettings = {
  heroTitle: "Domine\nO Próximo Nível.",
  heroSubtitle: "Sua biblioteca privada de alta performance, agora 100% online e sob seu comando.",
  heroImageUrl: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1964&auto=format&fit=crop",
  heroButtonText: "Começar Agora",
  heroButtonLink: "#vitrine"
};

const App: React.FC = () => {
  // --- ESTADOS ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content' | 'hero'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [adminTab, setAdminTab] = useState<'conteudo' | 'vitrine'>('conteudo');
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);

  // --- UTILITÁRIOS ---
  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    const displayMessage = typeof message === 'string' ? message : (message?.message || "Erro inesperado");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  // --- LISTENER DE AUTENTICAÇÃO REAL ---
  useEffect(() => {
    // Verificar sessão atual
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        handleSetUser(session.user);
      }
    });

    // Escutar mudanças
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        handleSetUser(session.user);
      } else {
        setCurrentUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleSetUser = (supabaseUser: any) => {
    const isAdmin = supabaseUser.email === 'admin@academia.com';
    setCurrentUser({
      id: supabaseUser.id,
      name: supabaseUser.user_metadata.full_name || supabaseUser.email?.split('@')[0] || 'Membro Elite',
      email: supabaseUser.email || '',
      isAdmin: isAdmin
    });
  };

  // --- BUSCA DE DADOS ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: mData, error: mError } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (mError) throw mError;

      const { data: sData, error: sError } = await supabase
        .from('settings')
        .select('*')
        .maybeSingle();

      if (!sError && sData) {
        setSettings({
          heroTitle: sData.hero_title || DEFAULT_SETTINGS.heroTitle,
          heroSubtitle: sData.hero_subtitle || DEFAULT_SETTINGS.heroSubtitle,
          heroImageUrl: sData.hero_image_url || DEFAULT_SETTINGS.heroImageUrl,
          heroButtonText: sData.hero_button_text || DEFAULT_SETTINGS.heroButtonText,
          heroButtonLink: sData.hero_button_link || DEFAULT_SETTINGS.heroButtonLink,
        });
      }

      const formattedData: Material[] = (mData || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type as MaterialType,
        category: m.category,
        description: m.description || '',
        imageUrl: m.image_url || '',
        videoUrl: m.video_url || '',
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      console.error("Erro Fetch:", e);
      addToast("Erro ao carregar dados da VPS.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- UPLOAD ---
  const handleFileUpload = async (file: File, type: 'image' | 'content' | 'hero') => {
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('materials').getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa do card pronta!");
      } else if (type === 'hero') {
        setSettings(prev => ({ ...prev, heroImageUrl: data.publicUrl }));
        addToast("Nova capa principal enviada!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Vídeo/PDF salvo!");
      }
    } catch (e: any) {
      addToast("Erro no upload: " + e.message, 'error');
    } finally {
      setIsUploading('none');
    }
  };

  // --- CONFIGURAÇÕES VITRINE ---
  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const payload = {
        hero_title: settings.heroTitle,
        hero_subtitle: settings.heroSubtitle,
        hero_image_url: settings.heroImageUrl,
        hero_button_text: settings.heroButtonText,
        hero_button_link: settings.heroButtonLink,
      };

      const { data: existing } = await supabase.from('settings').select('id').limit(1);

      let error;
      if (existing && existing.length > 0) {
        const res = await supabase.from('settings').update(payload).eq('id', existing[0].id);
        error = res.error;
      } else {
        const res = await supabase.from('settings').insert([payload]);
        error = res.error;
      }

      if (error) throw error;
      addToast("A vitrine foi atualizada para todos os membros!");
    } catch (e: any) {
      addToast("Erro ao salvar vitrine. Rode o SQL da tabela 'settings'.", "error");
    }
  };

  // --- AUTENTICAÇÃO ---
  const handleGoogleLogin = async () => {
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: window.location.origin
        }
      });
      if (error) throw error;
    } catch (e: any) {
      addToast(e.message, 'error');
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      if (isAuthMode === 'login') {
        const { error } = await supabase.auth.signInWithPassword({
          email: authEmail,
          password: authPassword,
        });
        if (error) throw error;
        addToast("Acesso concedido!");
      } else {
        const { error } = await supabase.auth.signUp({
          email: authEmail,
          password: authPassword,
          options: {
            data: {
              full_name: authName
            }
          }
        });
        if (error) throw error;
        addToast("Verifique seu e-mail para confirmar o cadastro!");
      }
    } catch (e: any) {
      addToast(e.message, 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setSelectedItem(null);
    addToast("Até breve!");
  };

  // --- CRUD MATERIAIS ---
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return addToast("Preencha Título e Capa", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      let error;
      if (isEditing && materialForm.id) {
        const res = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        error = res.error;
      } else {
        const res = await supabase.from('materials').insert([payload]);
        error = res.error;
      }
      if (error) throw error;

      addToast(isEditing ? "Alterado com sucesso!" : "Novo módulo lançado!");
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao publicar conteúdo.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Isso apagará o conteúdo para todos. Confirmar?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Removido da biblioteca.");
