                       <span className="px-6 py-3 glass rounded-2xl text-[11px] font-black uppercase tracking-[4px] border border-white/20 shadow-2xl backdrop-blur-3xl text-white">
                          {item.type === 'curso' ? 'Masterclass' : 'E-book Digital'}
                       </span>
                    </div>
                  </div>
                  <div className="p-12 flex flex-col flex-1">
                    <h3 className="text-3xl font-black mb-6 tracking-tighter leading-tight group-hover:text-purple-400 transition-colors">{item.title}</h3>
                    <p className="text-gray-500 text-lg leading-relaxed line-clamp-2 mb-10 italic opacity-80 font-medium">"{item.description || 'Descrição blindada pelo protocolo Vitalício.'}"</p>

                    <div className="mt-auto flex justify-between items-center pt-10 border-t border-white/5">
                      <div className="flex flex-col">
                         <span className="text-[11px] font-black text-gray-500 uppercase tracking-[4px] mb-2">{item.category}</span>
                         <span className="text-[10px] font-black text-purple-600 uppercase flex items-center gap-2"><Eye size={14}/> {item.views.toLocaleString()} acessos</span>
                      </div>
                      <button onClick={() => setSelectedItem(item)} className="p-6 bg-purple-600/10 text-purple-400 rounded-3xl hover:bg-purple-600 hover:text-white transition-all shadow-2xl border border-purple-500/20 active:scale-90 group-hover:scale-110">
                        <ArrowRight size={28}/>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-60 text-center opacity-10 flex flex-col items-center">
                 <Search size={120} className="mb-10" strokeWidth={1} />
                 <p className="text-5xl font-black uppercase tracking-[25px]">Vazio</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LogOut, Search, Grid, List, Book, PlayCircle, Plus, Trash2, Edit3, 
  LayoutDashboard, MessageSquare, Eye, CheckCircle, X, Send, 
  ArrowRight, Users, Layers, Star, RotateCcw, Loader2, ExternalLink, 
  Database, AlertCircle, Image as ImageIcon, Info, FileText, UploadCloud,
  Settings as SettingsIcon, Monitor, Sparkles, Link as LinkIcon
} from 'lucide-react';
import { User, Material, AppSettings, CATEGORIES, CATEGORY_ICONS, MaterialType } from './types';
import { supabase } from './supabase';

const getRandomGradient = () => {
  const gradients = [
    'from-indigo-500 via-purple-500 to-pink-500',
    'from-amber-400 via-orange-500 to-red-600',
    'from-cyan-400 via-blue-500 to-indigo-600',
    'from-emerald-400 via-teal-500 to-cyan-600',
    'from-fuchsia-500 via-purple-600 to-violet-700',
    'from-blue-600 via-indigo-700 to-purple-800'
  ];
  return gradients[Math.floor(Math.random() * gradients.length)];
};

const DEFAULT_SETTINGS: AppSettings = {
  heroTitle: "Domine\nO Próximo Nível.",
  heroSubtitle: "Sua biblioteca privada de alta performance, agora 100% online e sob seu comando.",
  heroImageUrl: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1964&auto=format&fit=crop",
  heroButtonText: "Começar Agora",
  heroButtonLink: "#vitrine"
};

const App: React.FC = () => {
  // --- ESTADOS ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthMode, setIsAuthMode] = useState<'login' | 'register'>('login');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authName, setAuthName] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isUploading, setIsUploading] = useState<'none' | 'image' | 'content' | 'hero'>('none');

  const [items, setItems] = useState<Material[]>([]);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [activeTab, setActiveTab] = useState<'todos' | 'curso' | 'ebook'>('todos');
  const [selectedItem, setSelectedItem] = useState<Material | null>(null);

  const [isEditing, setIsEditing] = useState(false);
  const [adminTab, setAdminTab] = useState<'conteudo' | 'vitrine'>('conteudo');
  const [materialForm, setMaterialForm] = useState<Partial<Material>>({
    title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: ''
  });

  const [toasts, setToasts] = useState<{id: string, message: string, type?: 'success' | 'error'}[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const contentInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);

  // --- UTILITÁRIOS ---
  const addToast = (message: any, type: 'success' | 'error' = 'success') => {
    const id = Date.now().toString();
    const displayMessage = typeof message === 'string' ? message : (message?.message || "Erro inesperado");
    setToasts(prev => [...prev, { id, message: displayMessage, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  // Helper para renderizar texto com links clicáveis
  const renderDescription = (text: string) => {
    if (!text) return null;
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);
    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a 
            key={i} 
            href={part} 
            target="_blank" 
            rel="noopener noreferrer" 
            className="text-purple-400 hover:text-purple-300 underline underline-offset-4 decoration-purple-500/50 hover:decoration-purple-400 inline-flex items-center gap-1 transition-all"
            onClick={(e) => e.stopPropagation()}
          >
            {part.length > 40 ? part.substring(0, 37) + '...' : part} <LinkIcon size={12} />
          </a>
        );
      }
      return part;
    });
  };

  // --- LISTENER DE AUTENTICAÇÃO REAL ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) handleSetUser(session.user);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) handleSetUser(session.user);
      else setCurrentUser(null);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleSetUser = (supabaseUser: any) => {
    const isAdmin = supabaseUser.email === 'admin@academia.com';
    setCurrentUser({
      id: supabaseUser.id,
      name: supabaseUser.user_metadata.full_name || supabaseUser.email?.split('@')[0] || 'Membro Elite',
      email: supabaseUser.email || '',
      isAdmin: isAdmin
    });
  };

  // --- BUSCA DE DADOS ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      const { data: mData, error: mError } = await supabase
        .from('materials')
        .select(`*, comments(*)`)
        .order('created_at', { ascending: false });

      if (mError) throw mError;

      const { data: sData, error: sError } = await supabase
        .from('settings')
        .select('*')
        .maybeSingle();

      if (!sError && sData) {
        setSettings({
          heroTitle: sData.hero_title || DEFAULT_SETTINGS.heroTitle,
          heroSubtitle: sData.hero_subtitle || DEFAULT_SETTINGS.heroSubtitle,
          heroImageUrl: sData.hero_image_url || DEFAULT_SETTINGS.heroImageUrl,
          heroButtonText: sData.hero_button_text || DEFAULT_SETTINGS.heroButtonText,
          heroButtonLink: sData.hero_button_link || DEFAULT_SETTINGS.heroButtonLink,
        });
      }

      const formattedData: Material[] = (mData || []).map(m => ({
        id: m.id,
        title: m.title,
        type: m.type as MaterialType,
        category: m.category,
        description: m.description || '',
        imageUrl: m.image_url || '',
        videoUrl: m.video_url || '',
        views: m.views || 0,
        gradient: m.gradient || getRandomGradient(),
        comments: (m.comments || []).map((c: any) => ({
          id: c.id,
          userName: c.user_name,
          text: c.text,
          timestamp: c.timestamp
        })),
        isReadBy: []
      }));

      setItems(formattedData);
      setDbStatus('connected');
    } catch (e: any) {
      setDbStatus('error');
      console.error("Erro Fetch:", e);
      addToast("Erro ao carregar dados da VPS.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- UPLOAD ---
  const handleFileUpload = async (file: File, type: 'image' | 'content' | 'hero') => {
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `${type}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('materials')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data } = supabase.storage.from('materials').getPublicUrl(filePath);

      if (type === 'image') {
        setMaterialForm(prev => ({ ...prev, imageUrl: data.publicUrl }));
        addToast("Capa do card pronta!");
      } else if (type === 'hero') {
        setSettings(prev => ({ ...prev, heroImageUrl: data.publicUrl }));
        addToast("Nova capa principal enviada!");
      } else {
        setMaterialForm(prev => ({ ...prev, videoUrl: data.publicUrl }));
        addToast("Vídeo/PDF salvo!");
      }
    } catch (e: any) {
      addToast("Erro no upload: " + e.message, 'error');
    } finally {
      setIsUploading('none');
    }
  };

  // --- CONFIGURAÇÕES VITRINE ---
  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const payload = {
        hero_title: settings.heroTitle,
        hero_subtitle: settings.heroSubtitle,
        hero_image_url: settings.heroImageUrl,
        hero_button_text: settings.heroButtonText,
        hero_button_link: settings.heroButtonLink,
      };

      const { data: existing } = await supabase.from('settings').select('id').limit(1);

      let error;
      if (existing && existing.length > 0) {
        const res = await supabase.from('settings').update(payload).eq('id', existing[0].id);
        error = res.error;
      } else {
        const res = await supabase.from('settings').insert([payload]);
        error = res.error;
      }

      if (error) throw error;
      addToast("A vitrine foi atualizada para todos os membros!");
    } catch (e: any) {
      addToast("Erro ao salvar vitrine. Rode o SQL da tabela 'settings'.", "error");
    }
  };

  // --- AUTENTICAÇÃO ---
  const handleGoogleLogin = async () => {
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: { redirectTo: window.location.origin }
      });
      if (error) throw error;
    } catch (e: any) {
      addToast(e.message, 'error');
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      if (isAuthMode === 'login') {
        const { error } = await supabase.auth.signInWithPassword({
          email: authEmail,
          password: authPassword,
        });
        if (error) throw error;
        addToast("Acesso concedido!");
      } else {
        const { error } = await supabase.auth.signUp({
          email: authEmail,
          password: authPassword,
          options: { data: { full_name: authName } }
        });
        if (error) throw error;
        addToast("Verifique seu e-mail para confirmar o cadastro!");
      }
    } catch (e: any) {
      addToast(e.message, 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setSelectedItem(null);
    addToast("Até breve!");
  };

  // --- CRUD MATERIAIS ---
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!materialForm.title || !materialForm.imageUrl) return addToast("Preencha Título e Capa", 'error');

    const payload = {
      title: materialForm.title,
      type: materialForm.type,
      category: materialForm.category,
      description: materialForm.description,
      image_url: materialForm.imageUrl,
      video_url: materialForm.videoUrl,
      gradient: materialForm.gradient || getRandomGradient()
    };

    try {
      let error;
      if (isEditing && materialForm.id) {
        const res = await supabase.from('materials').update(payload).eq('id', materialForm.id);
        error = res.error;
      } else {
        const res = await supabase.from('materials').insert([payload]);
        error = res.error;
      }
      if (error) throw error;

      addToast(isEditing ? "Alterado com sucesso!" : "Novo módulo lançado!");
      setIsEditing(false);
      setMaterialForm({ title: '', type: 'curso', category: CATEGORIES[0], description: '', imageUrl: '', videoUrl: '' });
      fetchData();
    } catch (e: any) {
      addToast("Erro ao publicar conteúdo.", 'error');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Isso apagará o conteúdo para todos. Confirmar?")) return;
    try {
      const { error } = await supabase.from('materials').delete().eq('id', id);
      if (error) throw error;
      addToast("Removido da biblioteca.");
      fetchData();
    } catch (e: any) {
      addToast("Erro ao deletar.", 'error');
    }
  };

  const handleComment = async (e: React.FormEvent, text: string) => {
    e.preventDefault();
    if (!selectedItem || !currentUser || !text.trim()) return;
    try {
      const { error } = await supabase.from('comments').insert([{
        material_id: selectedItem.id,
        user_name: currentUser.name,
        text: text,
        timestamp: new Date().toLocaleDateString('pt-BR')
      }]);
      if (error) throw error;
      fetchData();
      addToast("Feedback registrado!");
    } catch (e: any) {
      addToast("Erro ao comentar", 'error');
    }
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'Todos' || item.category === activeCategory;
      const matchesTab = activeTab === 'todos' || item.type === activeTab;
      return matchesSearch && matchesCategory && matchesTab;
    });
  }, [items, searchTerm, activeCategory, activeTab]);

  // --- LAYOUT PADRÃO ---
  const DashboardLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    return (
      <div className="min-h-screen bg-black text-white flex flex-col md:flex-row relative">
        <div className="fixed top-6 right-6 z-[100] space-y-3 pointer-events-none">
          {toasts.map(t => (
            <div key={t.id} className={`animate-slide-in glass px-6 py-4 rounded-2xl border-l-4 pointer-events-auto flex items-center gap-3 shadow-2xl ${t.type === 'error' ? 'border-red-500 bg-red-500/5' : 'border-purple-500'}`}>
              {t.type === 'error' ? <AlertCircle size={18} className="text-red-400" /> : <CheckCircle size={18} className="text-purple-400" />}
              <span className="text-xs font-bold">{t.message}</span>
            </div>
          ))}
        </div>

        <aside className="w-full md:w-64 lg:w-80 glass border-r border-white/10 p-8 flex flex-col gap-10 bg-[#050505]/98 backdrop-blur-3xl z-50">
          <div className="flex items-center gap-4 px-2">
            <div className="p-3 rounded-2xl bg-gradient-primary shadow-[0_10px_30px_rgba(147,51,234,0.3)]"><Layers size={24} /></div>
            <h2 className="text-2xl font-black text-gradient-primary tracking-tighter">VITALÍCIO</h2>
          </div>

          <div className="p-6 rounded-[2rem] glass-card border border-white/10 flex items-center gap-5">
            <div className="w-12 h-12 rounded-2xl bg-gradient-primary flex items-center justify-center font-black text-lg shadow-xl">
              {currentUser?.name ? currentUser.name[0] : 'U'}
            </div>
            <div className="min-w-0">
              <p className="text-sm font-black truncate">{currentUser?.name}</p>
              <p className={`text-[10px] uppercase font-black tracking-widest ${currentUser?.isAdmin ? 'text-purple-400' : 'text-gray-500'}`}>
                {currentUser?.isAdmin ? 'ADMINISTRADOR' : 'MEMBRO ELITE'}
              </p>
            </div>
          </div>

          <nav className="space-y-1 overflow-y-auto scrollbar-hide flex-1">
            <p className="text-[10px] font-black text-gray-700 uppercase tracking-[4px] mb-6 ml-4">Biblioteca</p>
            {['Todos', ...CATEGORIES].map(cat => {
              const Icon = CATEGORY_ICONS[cat] || LayoutDashboard;
              return (
                <button key={cat} onClick={() => { setActiveCategory(cat); if(cat !== 'Todos') document.getElementById('vitrine')?.scrollIntoView({behavior:'smooth'}); }} className={`w-full text-left px-6 py-5 rounded-3xl text-xs font-black transition-all flex items-center gap-5 ${activeCategory === cat ? 'bg-purple-600 text-white shadow-[0_15px_40px_rgba(147,51,234,0.3)] translate-x-1' : 'text-gray-500 hover:bg-white/5 hover:text-white'}`}>
                  <Icon size={20} /> {cat}
                </button>
              );
            })}
          </nav>

          <div className="mt-auto pt-6 border-t border-white/5 space-y-4">
             <div className="text-[9px] font-black uppercase text-gray-700 flex items-center gap-3 px-4 py-2 bg-white/5 rounded-xl">
               <div className={`w-2 h-2 rounded-full ${dbStatus === 'connected' ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
               VPS: {dbStatus === 'connected' ? 'Operacional' : 'Offline'}
            </div>
            <button onClick={handleLogout} className="w-full flex items-center justify-center gap-4 px-8 py-5 rounded-3xl bg-red-500/5 text-red-400 font-black text-xs hover:bg-red-500/10 transition-all border border-red-500/10">
              <LogOut size={18} /> Encerrar Sessão
            </button>
          </div>
        </aside>

        <main className="flex-1 overflow-y-auto scrollbar-hide flex flex-col relative">
          <header className="sticky top-0 z-40 px-10 py-8 glass border-b border-white/5 flex items-center justify-between bg-black/40 backdrop-blur-2xl">
            <div className="flex-1 max-w-2xl relative group">
              <Search className="absolute left-7 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-purple-500 transition-colors" size={20} />
              <input type="text" placeholder="Pesquisar em toda a academia..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full bg-white/[0.03] border border-white/10 rounded-[2rem] pl-16 pr-8 py-5 text-sm outline-none focus:ring-2 focus:ring-purple-500/20 focus:border-purple-500/40 transition-all placeholder:text-gray-600" />
            </div>
            <div className="flex items-center gap-5 ml-8">
              <button onClick={fetchData} className="p-5 bg-white/5 rounded-2xl hover:bg-white/10 text-gray-500 hover:text-white transition-all border border-white/5"><RotateCcw size={20} /></button>
              <div className="flex bg-white/5 p-1.5 rounded-2xl border border-white/10 backdrop-blur-xl">
                <button onClick={() => setViewMode('grid')} className={`p-3 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-purple-600 text-white shadow-xl' : 'text-gray-500'}`}><Grid size={20} /></button>
                <button onClick={() => setViewMode('list')} className={`p-3 rounded-xl transition-all ${viewMode === 'list' ? 'bg-purple-600 text-white shadow-xl' : 'text-gray-500'}`}><List size={20} /></button>
              </div>
            </div>
          </header>

          <div className="p-8 md:p-16 pb-40 flex-1">
            {children}
          </div>
        </main>

        {selectedItem && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 md:p-10 animate-fade-in">
            <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={() => setSelectedItem(null)}></div>
            <div className="relative w-full max-w-[1400px] h-full max-h-[90vh] flex flex-col lg:flex-row glass border border-white/10 rounded-[4rem] shadow-[0_0_100px_rgba(0,0,0,1)] overflow-hidden">
              <div className="flex-1 overflow-y-auto p-12 lg:p-20 bg-black scrollbar-hide">
                <div className="flex justify-between items-start mb-16">
                  <div className="flex items-center gap-8">
                    <div className={`p-6 rounded-3xl shadow-2xl bg-gradient-to-br ${selectedItem.gradient}`}>
                      {selectedItem.type === 'curso' ? <PlayCircle size={48} /> : <Book size={48} />}
