                    <div>
                      <h2 className="text-4xl lg:text-6xl font-black tracking-tighter leading-none mb-4">{selectedItem.title}</h2>
                      <div className="flex gap-4">
                        <span className="px-5 py-2 glass rounded-full text-[10px] font-black uppercase tracking-widest text-purple-400">{selectedItem.category}</span>
                        <span className="px-5 py-2 glass rounded-full text-[10px] font-black uppercase tracking-widest text-gray-500 flex items-center gap-2"><Eye size={12}/> {selectedItem.views} Acessos</span>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => setSelectedItem(null)} className="p-4 bg-white/5 rounded-full hover:bg-red-500/20 hover:text-red-400 transition-all border border-white/10"><X size={32} /></button>
                </div>

                <div className="aspect-video w-full rounded-[4rem] bg-gray-950 overflow-hidden mb-16 border border-white/5 relative group shadow-3xl">
                  <img src={selectedItem.imageUrl} className="w-full h-full object-cover opacity-30 group-hover:scale-105 transition-transform duration-1000" alt="" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <a href={selectedItem.videoUrl} target="_blank" className="p-16 rounded-full bg-purple-600/10 border border-purple-500/50 hover:bg-purple-600 hover:scale-110 transition-all shadow-[0_0_80px_rgba(147,51,234,0.4)] backdrop-blur-md">
                      {selectedItem.type === 'curso' ? <PlayCircle size={80} fill="white" /> : <Book size={80} fill="white" />}
                    </a>
                  </div>
                </div>
                <div className="max-w-4xl">
                  <h3 className="text-2xl font-black mb-8 border-b border-white/5 pb-6 flex items-center gap-4 text-purple-400 uppercase tracking-widest text-[12px]">Objetivo do Módulo</h3>
