                  <div className="p-12 flex flex-col flex-1">
                    <h3 className="text-3xl font-black mb-6 tracking-tighter leading-tight group-hover:text-purple-400 transition-colors">{item.title}</h3>
                    <div className="text-gray-500 text-lg leading-relaxed line-clamp-3 mb-10 italic opacity-80 font-medium">
                      {renderDescription(item.description || 'Descrição blindada pelo protocolo Vitalício.')}
                    </div>

                    <div className="mt-auto flex justify-between items-center pt-10 border-t border-white/5">
                      <div className="flex flex-col">
                         <span className="text-[11px] font-black text-gray-500 uppercase tracking-[4px] mb-2">{item.category}</span>
                         <span className="text-[10px] font-black text-purple-600 uppercase flex items-center gap-2"><Eye size={14}/> {item.views.toLocaleString()} acessos</span>
                      </div>
                      <button onClick={() => setSelectedItem(item)} className="p-6 bg-purple-600/10 text-purple-400 rounded-3xl hover:bg-purple-600 hover:text-white transition-all shadow-2xl border border-purple-500/20 active:scale-90 group-hover:scale-110">
                        <ArrowRight size={28}/>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default App;
